-- Schema for Domain: equipment | Business: Mining | Version: v1_mvm
-- Generated on: 2026-05-05 14:20:15

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `mining_ecm`.`equipment` COMMENT 'Owns the master register of all mining fleet and fixed plant assets including drills, haul trucks, shovels, conveyors, and processing equipment. Tracks OEE, MTBF, MTTR, utilisation, availability metrics, telematics, and fuel consumption sourced from MineStar and Infor EAM.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`asset` (
    `asset_id` BIGINT COMMENT 'Unique surrogate identifier for each physical mining asset record in the master register. Primary key for the asset data product.',
    `asset_class_id` BIGINT COMMENT 'Foreign key linking to equipment.asset_class. Business justification: The asset table currently stores asset_class as a STRING attribute, but a dedicated asset_class master table exists with PK asset_class_id. This is a classic denormalization pattern that should be nor',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Each asset is owned by a cost centre for maintenance budget allocation, depreciation charging, and AISC unit cost reporting. The asset table carries a denormalized cost_centre_code; replacing it with ',
    `counterparty_id` BIGINT COMMENT 'Foreign key linking to customer.counterparty. Business justification: Mining assets are frequently leased, hired, or jointly owned with external counterparties. The asset register must reference the owning/leasing counterparty for contract management, lease expiry track',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Every physical mining asset (haul truck, excavator, drill rig) is capitalised in the fixed asset register for depreciation, NBV reporting, and IFRS/AASB116 compliance. EAM-to-FAR reconciliation is a m',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Core EAM business process: every physical asset is installed at a functional location. Maintenance planners use asset-to-FL assignment for work order routing, PM scheduling, and statutory compliance r',
    `hazard_id` BIGINT COMMENT 'Foreign key linking to hse.hazard. Business justification: Each mining asset (haul truck, crusher, conveyor) is associated with a primary hazard profile (rollover, entrapment, conveyor nip). Linking assets to their primary hazard enables pre-start checklist g',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: In multi-entity mining groups, assets are legally owned by specific entities for tax, insurance, and intercompany transfer purposes. Asset legal ownership drives transfer pricing, insurance valuations',
    `mine_site_id` BIGINT COMMENT 'Foreign key linking to mine.mine_site. Business justification: Asset register management requires knowing which mine site each asset is deployed at for maintenance planning, cost allocation, and capital budgeting. A mining engineer expects every asset to have a h',
    `parent_asset_id` BIGINT COMMENT 'Reference to the parent asset in a multi-component asset hierarchy (e.g., an engine assembly belonging to a haul truck). Enables parent-child asset relationship modelling for complex equipment units. Null for top-level assets.',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Mining assets are often dedicated to specific product streams (iron ore haul trucks, coal handling equipment). Production planning, asset allocation, and performance reporting require tracking which p',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Mining equipment operates within specific tenement boundaries. Real operations track which licence area each asset is deployed to for regulatory compliance, expenditure allocation, and operational pla',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Assets permanently stationed at a TSF (decant pumps, slurry pipelines, monitoring equipment) must be registered against the specific facility for asset register management, closure liability attributi',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Mining equipment has OEM suppliers; tracking vendor enables warranty claims, parts procurement, and supplier performance analysis. Real business process: OEM parts sourcing and warranty management. Ne',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Assets under construction or acquired via capital projects are linked to a WBS element for CAPEX tracking and project cost roll-up. The asset table carries a denormalized wbs_element text field; a pro',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'Original capital expenditure (CAPEX) purchase price of the asset in the reporting currency. Used for depreciation calculations, asset register valuation, and capital replacement planning under IAS 16 and IFRS.',
    `asset_name` STRING COMMENT 'Human-readable descriptive name of the asset, typically combining equipment type and fleet number (e.g., Haul Truck HT-042, SAG Mill 01). Used in reporting, dashboards, and work orders.',
    `commissioning_date` DATE COMMENT 'Date the asset was formally commissioned and placed into operational service at the mine site. Marks the start of the assets operational lifecycle for maintenance scheduling, warranty tracking, and depreciation under IFRS.',
    `cost_center_code` STRING COMMENT 'SAP S/4HANA cost center code to which the assets operating expenditure (OPEX) and maintenance costs are allocated. Enables financial reporting by asset and supports OPEX tracking against budget.',
    `criticality_rating` STRING COMMENT 'Maintenance criticality classification of the asset based on its impact on production, safety, and environmental compliance if it fails. Drives maintenance strategy selection, spare parts stocking levels, and Overall Equipment Effectiveness (OEE) prioritisation.. Valid values are `Critical|High|Medium|Low`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the acquisition cost and financial values associated with the asset (e.g., AUD, USD, ZAR). Supports multi-currency asset register reporting.. Valid values are `[A-Z]{3}`',
    `decommissioning_date` DATE COMMENT 'Date the asset was permanently removed from operational service and decommissioned. Null for assets still in service. Used for asset lifecycle reporting, capital replacement planning, and mine rehabilitation cost estimation.',
    `eam_asset_code` STRING COMMENT 'Source system identifier for the asset record in Infor EAM. Used for system-of-record traceability and integration with maintenance work orders, preventive maintenance schedules, and asset lifecycle management.',
    `engine_power_kw` DECIMAL(18,2) COMMENT 'OEM-rated engine or motor power output of the asset in kilowatts (kW). Used for fuel consumption benchmarking, energy efficiency analysis, and equipment selection for mine planning. Null for non-powered assets.',
    `fleet_number` STRING COMMENT 'Operational fleet number assigned to the asset at the mine site. Used by operators, dispatchers, and Fleet Management System (FMS) to identify and track the asset in the field. Sourced from Caterpillar MineStar and Infor EAM.',
    `fuel_tank_capacity_litres` DECIMAL(18,2) COMMENT 'Maximum fuel tank capacity of the asset in litres. Used for fuel logistics planning, refuelling scheduling, and fuel consumption rate benchmarking. Null for electric or non-fuel-powered assets.',
    `fuel_type` STRING COMMENT 'Primary energy source or fuel type powering the asset. Used for fuel consumption tracking, emissions reporting under GRI Mining and Metals Sector Supplement, and fleet electrification planning.. Valid values are `Diesel|Electric|LNG|Hydrogen|Hybrid|Hydraulic`',
    `is_mobile` BOOLEAN COMMENT 'Indicates whether the asset is a mobile mining unit (True) such as a haul truck, excavator, or drill rig, or a fixed plant asset (False) such as a conveyor, crusher, or mill. Drives different tracking, reporting, and maintenance workflows.',
    `last_major_overhaul_date` DATE COMMENT 'Date of the most recent major overhaul or rebuild performed on the asset. Used to assess remaining component life, plan future overhauls, and calculate Mean Time Between Failures (MTBF) in the maintenance management system.',
    `location_description` STRING COMMENT 'Descriptive operational location of the asset within the mine site (e.g., Pit 3 North Wall, Processing Plant - Grinding Circuit, ROM Pad). Complements the site code with granular positional context for maintenance and dispatch.',
    `manufacture_year` STRING COMMENT 'Calendar year in which the asset was manufactured by the OEM. Used to calculate asset age, depreciation schedules, and Life of Mine (LOM) planning for fleet replacement.',
    `model` STRING COMMENT 'OEM model designation of the asset (e.g., CAT 793F, Komatsu 930E, Sandvik DR461i). Used for spare parts management, maintenance procedures, and performance benchmarking against OEM specifications.',
    `next_scheduled_service_date` DATE COMMENT 'Date of the next planned preventive maintenance service for the asset as scheduled in Infor EAM. Used for maintenance planning, production scheduling, and availability forecasting.',
    `odometer_km` DECIMAL(18,2) COMMENT 'Current cumulative odometer reading in kilometres for mobile assets. Used alongside SMR hours for maintenance scheduling, tyre life management, and haul road condition monitoring. Null for fixed plant assets.',
    `operating_weight_tonnes` DECIMAL(18,2) COMMENT 'OEM-rated operating weight of the asset in metric tonnes. Used for road and haul route load limit compliance, ground bearing pressure calculations, and mine infrastructure design.',
    `operational_status` STRING COMMENT 'Current operational lifecycle status of the asset indicating whether it is available for production, undergoing maintenance, on standby, or permanently decommissioned. Drives availability calculations and maintenance scheduling in Infor EAM and MineStar.. Valid values are `Active|Standby|Under Maintenance|Decommissioned|Commissioned`',
    `ownership_type` STRING COMMENT 'Indicates whether the asset is company-owned, leased under a finance or operating lease, short-term hired, or contractor-supplied. Drives financial treatment under IFRS 16 and determines maintenance responsibility.. Valid values are `Owned|Leased|Hired|Contractor`',
    `payload_capacity_tonnes` DECIMAL(18,2) COMMENT 'OEM-rated maximum payload capacity of the asset in metric tonnes. Applicable to haul trucks, loaders, and material handling equipment. Used for production planning, haulage cycle optimisation, and OEE calculations. Null for fixed plant assets.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when the asset record was first created in the master register. Used for data lineage, audit trail, and compliance with asset register governance requirements.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the asset record was most recently updated in the master register. Used for change tracking, data quality monitoring, and integration refresh management in the Databricks Silver Layer.',
    `scada_tag` STRING COMMENT 'SCADA tag identifier used to link the asset to its real-time process data streams in the OSIsoft PI System historian. Applicable primarily to fixed plant assets such as conveyors, crushers, mills, and processing equipment.',
    `serial_number` STRING COMMENT 'Original Equipment Manufacturer (OEM) serial number uniquely identifying the physical asset unit. Used for warranty tracking, OEM service records, and regulatory compliance. Sourced from Infor EAM.',
    `site_code` STRING COMMENT 'Code identifying the mine site where the asset is currently assigned and operated. Enables site-level fleet reporting, OEE benchmarking, and cross-site asset utilisation analysis. Sourced from SAP S/4HANA Plant Master.',
    `smr_hours` DECIMAL(18,2) COMMENT 'Current cumulative Service Meter Reading (SMR) in engine hours recorded on the asset. Used as the primary trigger for preventive maintenance scheduling, component life tracking, and MTBF calculations in Infor EAM.',
    `tag` STRING COMMENT 'Internal asset tag or barcode label affixed to the physical asset for inventory and maintenance identification. Distinct from fleet number and serial number. Sourced from Infor EAM.',
    `telematics_unit_code` STRING COMMENT 'Identifier of the onboard telematics or GPS tracking unit installed on the asset. Used to link real-time positional and operational data from Caterpillar MineStar and OSIsoft PI System for fleet management and equipment health monitoring.',
    `useful_life_years` STRING COMMENT 'OEM-specified or engineering-assessed useful operational life of the asset in years. Used for straight-line depreciation calculations, Life of Mine (LOM) fleet planning, and capital replacement scheduling under IAS 16.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the OEM warranty for the asset expires. Used to trigger warranty claim processes, plan post-warranty maintenance strategies, and manage OEM service agreements in Infor EAM and Pronto Xi.',
    CONSTRAINT pk_asset PRIMARY KEY(`asset_id`)
) COMMENT 'Master register of all mining fleet and fixed plant assets including haul trucks, excavators, drills, shovels, dozers, graders, conveyors, crushers, mills, and processing equipment. Each record represents a unique physical asset identified by fleet number and serial number. Captures OEM manufacturer, model, year of manufacture, commissioning date, current operational status, assigned site, and parent-child relationships for multi-component assets. Sourced from Infor EAM. Serves as the SSOT for equipment identity, classification, and lifecycle status across all mine sites.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`asset_class` (
    `asset_class_id` BIGINT COMMENT 'Unique surrogate identifier for each asset class record in the mining equipment classification hierarchy. Primary key for the asset_class reference master.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Mining fleet planning and capex budgeting is commodity-specific — crusher asset classes for copper differ from iron ore. Asset class configuration (payload capacity, PM intervals, OEE targets) is desi',
    `asset_life_years` DECIMAL(18,2) COMMENT 'Expected useful life of the asset class expressed in calendar years for financial depreciation and LOM planning purposes. Used alongside useful_life_operating_hours to determine the binding depreciation constraint. Supports CAPEX modelling and NPV/IRR analysis.',
    `capacity_unit_of_measure` STRING COMMENT 'Unit of measure for the nominal_capacity field (e.g., t for payload tonnes, t/h for throughput tonnes per hour, m3 for bucket/bowl volume, mm for drill hole diameter, kW for power rating). Ensures correct interpretation of capacity values across equipment types. [ENUM-REF-CANDIDATE: t|t/h|m3|m3/h|mm|kW|MW|m|km/h — 9 candidates stripped; promote to reference product]',
    `capex_budget_category` STRING COMMENT 'Capital expenditure (CAPEX) budget category under which assets of this class are typically funded. Sustaining CAPEX covers replacement of existing capacity; expansion CAPEX covers new capacity additions. Used for capital allocation, LOM planning, and financial reporting under IFRS.. Valid values are `sustaining|expansion|replacement|greenfield|brownfield`',
    `class_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the asset class within the equipment classification hierarchy (e.g., HT-320T for 320-tonne haul truck class, SAG-36FT for 36-foot SAG mill class). Used as the business key across ERP, EAM, and FMS systems.. Valid values are `^[A-Z0-9]{3,12}$`',
    `class_description` STRING COMMENT 'Detailed narrative description of the asset class including its primary function, operational context within the mine, and key distinguishing characteristics. Supports procurement specifications and capital budgeting documentation.',
    `class_name` STRING COMMENT 'Human-readable name of the asset class describing the equipment type and key specification (e.g., Ultra-Class Haul Truck 320T, Semi-Autogenous Grinding Mill 36ft, Rotary Blasthole Drill 270mm). Used in reports, dashboards, and maintenance planning documents.',
    `class_status` STRING COMMENT 'Current lifecycle status of the asset class record. Active classes are in current use for fleet planning and procurement. Phasing_out classes are being replaced by newer models. Retired classes are no longer procured but may still have operating assets. Controls visibility in procurement and planning systems.. Valid values are `active|inactive|phasing_out|retired`',
    `co2_emission_factor_kg_per_hr` DECIMAL(18,2) COMMENT 'Carbon dioxide (CO2) emission factor for assets of this class in kilograms per operating hour, derived from OEM fuel consumption specifications and applicable emission conversion factors. Used for Scope 1 greenhouse gas emissions reporting under GRI, ICMM, and regulatory environmental disclosure requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this asset class record was first created in the system, recorded in ISO 8601 format with timezone offset. Provides audit trail for data governance and lineage tracking in the Databricks lakehouse silver layer.',
    `critical_equipment_flag` BOOLEAN COMMENT 'Indicates whether this asset class is designated as critical equipment whose failure would cause significant production loss, safety risk, or environmental incident. Critical equipment classes receive priority maintenance resourcing, enhanced spare parts stockholding, and elevated monitoring frequency in OSIsoft PI System.',
    `depreciation_method` STRING COMMENT 'Accounting depreciation method applied to assets of this class for financial reporting and capital budgeting purposes. Units_of_production is common for mining equipment tied to ore tonnes mined. Aligns with IAS 16 and IFRS reporting requirements.. Valid values are `straight_line|units_of_production|declining_balance|sum_of_years_digits`',
    `effective_from_date` DATE COMMENT 'Date from which this asset class definition became effective and valid for use in fleet planning, procurement, and maintenance scheduling. Supports temporal validity tracking for the asset class master record.',
    `effective_to_date` DATE COMMENT 'Date on which this asset class definition ceases to be effective (nullable for open-ended active classes). Used to manage class version transitions when OEM specifications change or when a class is retired from the fleet register.',
    `equipment_type` STRING COMMENT 'Functional equipment type within the fleet category (e.g., haul_truck, excavator, blasthole_drill, dozer, grader, water_cart, light_vehicle, conveyor, crusher, sag_mill, ball_mill, hpgr, flotation_cell, thickener, stacker, reclaimer). [ENUM-REF-CANDIDATE: haul_truck|excavator|blasthole_drill|dozer|grader|water_cart|light_vehicle|conveyor|crusher|sag_mill|ball_mill|hpgr|flotation_cell|thickener|stacker|reclaimer — promote to reference product]',
    `fleet_category` STRING COMMENT 'Top-level classification distinguishing between mobile fleet assets (haul trucks, excavators, drills, dozers, graders, water carts, light vehicles) and fixed plant assets (conveyors, crushers, mills, flotation cells, thickeners). Drives maintenance strategy, depreciation treatment, and fleet sizing models.. Valid values are `mobile_fleet|fixed_plant`',
    `fuel_consumption_rate_l_per_hr` DECIMAL(18,2) COMMENT 'Standard OEM-rated fuel consumption rate for assets of this class in litres per operating hour under typical mine operating conditions. Used for fuel budget forecasting, OPEX modelling, carbon emissions estimation, and fleet energy management reporting.',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether assets of this class involve or carry hazardous materials (e.g., explosives transport vehicles, acid handling equipment in SX-EW circuits, cyanide dosing systems in leaching). Triggers mandatory HSE compliance controls, PPE requirements, and IsoMetrix risk assessment workflows.',
    `infor_eam_class_code` STRING COMMENT 'Corresponding asset class identifier in the Infor EAM system used for asset lifecycle management, preventive maintenance scheduling, and work order management. Enables bi-directional data reconciliation between the lakehouse silver layer and the operational EAM system.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this asset class record was most recently modified, recorded in ISO 8601 format with timezone offset. Used for change data capture (CDC), data lineage tracking, and audit compliance in the silver layer.',
    `maintenance_strategy_type` STRING COMMENT 'Primary maintenance strategy applied to assets of this class: time_based (fixed interval PM schedules), condition_based (triggered by measured condition thresholds), predictive (AI/ML-driven failure prediction from sensor data), or run_to_failure (for low-criticality components). Drives maintenance planning in Infor EAM and CMMS scheduling.. Valid values are `time_based|condition_based|predictive|run_to_failure`',
    `major_overhaul_interval_hours` STRING COMMENT 'Operating hour interval at which a major component overhaul or rebuild is required for assets of this class (e.g., 20,000 hours for engine rebuild, 40,000 hours for full structural overhaul). Drives long-range maintenance CAPEX planning and LOM cost modelling.',
    `minestar_equipment_class_code` STRING COMMENT 'Equipment class identifier as defined in the Caterpillar MineStar Fleet Management System (FMS). Used to align telematics data, productivity metrics, and equipment health signals from MineStar with the enterprise asset class master.',
    `nominal_capacity` DECIMAL(18,2) COMMENT 'Principal quantitative capacity specification for the asset class expressed in the relevant unit of measure (e.g., payload tonnes for haul trucks, throughput tonnes per hour for mills and crushers, bucket capacity m³ for excavators, hole diameter mm for drills). The principal numeric fact defining the classs productive capability.',
    `oem_category` STRING COMMENT 'Original Equipment Manufacturer (OEM) product category or model family designation as defined by the manufacturer (e.g., Caterpillar 793, Komatsu 930E, Liebherr T 284, Sandvik DR416i). Used for OEM warranty tracking, parts compatibility, and service agreement alignment.',
    `oem_name` STRING COMMENT 'Name of the original equipment manufacturer for this asset class (e.g., Caterpillar, Komatsu, Liebherr, Sandvik, Metso, FLSmidth). Used for vendor relationship management, warranty claims, and procurement sourcing strategies.',
    `operating_weight_tonnes` DECIMAL(18,2) COMMENT 'Gross operating weight of the asset class in metric tonnes as specified by the OEM. Used for haul road design, bridge load ratings, ground bearing pressure calculations, and site infrastructure planning.',
    `pm_interval_hours` STRING COMMENT 'Standard preventive maintenance (PM) service interval in operating hours for assets of this class (e.g., 250 hours for minor service, 1000 hours for major service). Defines the base PM scheduling cadence in the CMMS and Infor EAM maintenance plans.',
    `power_rating_kw` DECIMAL(18,2) COMMENT 'Installed engine or motor power rating for the asset class in kilowatts (kW) as specified by the OEM. Used for energy consumption modelling, fuel burn estimation, electrical infrastructure planning, and OPEX forecasting.',
    `replacement_cost_usd` DECIMAL(18,2) COMMENT 'Current estimated replacement cost for a single asset unit of this class in US dollars. Used for insurance valuation, capital budgeting, CAPEX planning, and NPV/IRR analysis in LOM financial models. Classified as confidential due to commercial sensitivity in procurement negotiations.',
    `sap_asset_class_code` STRING COMMENT 'Corresponding asset class code (ANLKL) in SAP S/4HANA Fixed Asset Accounting (FI-AA) module. Used to reconcile the equipment master data with the financial asset register and ensure consistent depreciation treatment across ERP and EAM systems.. Valid values are `^[A-Z0-9]{4,8}$`',
    `size_capacity_tier` STRING COMMENT 'Standardised size and capacity tier classification for the asset class used in fleet sizing models and capital budgeting (e.g., ultra_class for 300T+ haul trucks, large for 150-299T, medium for 90-149T). Enables fleet mix optimisation and benchmarking across mine sites.. Valid values are `ultra_class|large|medium|small|light`',
    `target_availability_pct` DECIMAL(18,2) COMMENT 'Target physical availability percentage for assets of this class expressed as a percentage (e.g., 85.00 for 85%). Physical availability is the proportion of scheduled time the equipment is mechanically available for operation. Used as the benchmark for OEE calculations and maintenance performance KPIs.',
    `target_mtbf_hours` DECIMAL(18,2) COMMENT 'Target Mean Time Between Failures (MTBF) in operating hours for assets of this class. MTBF is the average operating time between unplanned mechanical failures. Used to set maintenance performance benchmarks, evaluate reliability improvement initiatives, and support predictive maintenance model calibration.',
    `target_mttr_hours` DECIMAL(18,2) COMMENT 'Target Mean Time To Repair (MTTR) in hours for assets of this class. MTTR measures the average time required to restore equipment to operational status following an unplanned failure. Used to benchmark maintenance crew efficiency and spare parts availability strategies.',
    `target_oee_pct` DECIMAL(18,2) COMMENT 'Target Overall Equipment Effectiveness (OEE) percentage for assets of this class, representing the combined product of availability, utilisation, and performance rate (e.g., 65.00 for 65%). OEE is the primary productivity benchmark for mining equipment classes used in production reporting and capital justification.',
    `target_utilisation_pct` DECIMAL(18,2) COMMENT 'Target utilisation percentage for assets of this class expressed as a percentage of available hours actually used for productive work (e.g., 75.00 for 75%). Distinct from availability — utilisation measures productive use of available time. Used in fleet sizing models and production planning.',
    `telematics_enabled_flag` BOOLEAN COMMENT 'Indicates whether assets of this class are equipped with telematics and real-time monitoring capability integrated with Caterpillar MineStar or OSIsoft PI System. Determines data availability for real-time OEE tracking, predictive maintenance, and fuel consumption monitoring.',
    `useful_life_operating_hours` STRING COMMENT 'Expected useful life of the asset class expressed in total operating hours as defined by OEM specifications and mine engineering standards (e.g., 80,000 hours for a large haul truck, 120,000 hours for a SAG mill). Drives depreciation schedules, LOM capital replacement planning, and fleet renewal strategies.',
    CONSTRAINT pk_asset_class PRIMARY KEY(`asset_class_id`)
) COMMENT 'Reference classification hierarchy for mining equipment types organised into mobile fleet (haul trucks, excavators, drills, dozers, graders, water carts, light vehicles) and fixed plant (conveyors, crushers, SAG mills, ball mills, HPGR, flotation cells, thickeners, stackers, reclaimers). Each class defines OEM category, asset class code, size/capacity tier, expected useful life in operating hours, depreciation method, maintenance strategy type (time-based, condition-based, predictive), and target availability percentage. Serves as the reference master for fleet sizing models, maintenance planning, and capital budgeting.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`fleet_assignment` (
    `fleet_assignment_id` BIGINT COMMENT 'Unique surrogate identifier for each fleet assignment record in the MineStar Fleet Management System. Primary key for the fleet_assignment data product.',
    `area_id` BIGINT COMMENT 'Reference to the mine area, pit, bench, or processing circuit to which the fleet asset is operationally assigned. Links to the mine location/area master.',
    `asset_id` BIGINT COMMENT 'Reference to the mobile fleet asset (haul truck, drill, dozer, grader, loader, etc.) being assigned. Links to the equipment master register sourced from Infor EAM.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Fleet assignments drive cost allocation — equipment hours, fuel, and operator costs per assignment are charged to a cost centre for mining vs processing vs development cost reporting. Dispatch systems',
    `production_schedule_id` BIGINT COMMENT 'Reference to the mine production schedule that this fleet assignment supports. Links to the production schedule in mine.production_schedule.',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Mining fleet dispatch requires a valid risk assessment for the work area before equipment is assigned. Links fleet assignments to the governing risk assessment for pre-task risk management, regulatory',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Each fleet assignment moves or processes a specific saleable product. Dispatch systems track product per assignment for production reconciliation, grade control, and stockpile management. Material_typ',
    `shift_report_id` BIGINT COMMENT 'Foreign key linking to mine.shift_report. Business justification: Fleet assignments are dispatched within a shift and must be traceable to the shift report for that shift. Shift supervisors reconcile all fleet assignments against the shift report to validate equipme',
    `shipment_nomination_id` BIGINT COMMENT 'Foreign key linking to sales.shipment_nomination. Business justification: Vessel loading fleet assignment: port and terminal operations assign specific equipment (reclaimers, stackers, conveyors, loaders) to execute each shipment nomination. Tracking which fleet assignment ',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Fleet assignments occur within specific tenement areas. Mining operations must track which licence area work is performed in for expenditure reporting, compliance with tenement conditions, and allocat',
    `assignment_duration_minutes` STRING COMMENT 'The actual elapsed duration of the fleet assignment in minutes, calculated from assignment start to end timestamps. Stored as a business field for shift reporting and OEE (Overall Equipment Effectiveness) analysis without requiring real-time computation.',
    `assignment_end_timestamp` TIMESTAMP COMMENT 'The date and time when the fleet asset completed or was released from its operational assignment. Null if the assignment is still active. Used to calculate assignment duration and shift utilisation.',
    `assignment_number` STRING COMMENT 'Externally-known business identifier for the fleet assignment, generated by MineStar Fleet Management System. Used for cross-system referencing, dispatch communications, and operational reporting.. Valid values are `^FA-[0-9]{4}-[0-9]{6}$`',
    `assignment_start_timestamp` TIMESTAMP COMMENT 'The date and time when the fleet asset commenced its operational assignment at the designated mine area or task. This is the principal real-world event time for the assignment lifecycle.',
    `assignment_status` STRING COMMENT 'Current lifecycle state of the fleet assignment. planned indicates a future assignment not yet commenced; active indicates the equipment is currently deployed; completed indicates the assignment has concluded; cancelled indicates the assignment was voided before commencement; suspended indicates a temporary halt due to breakdown, weather, or safety hold.. Valid values are `planned|active|completed|cancelled|suspended`',
    `bench_level` STRING COMMENT 'The specific bench elevation or level within the pit to which the fleet asset is assigned, expressed as a mine elevation reference (e.g., RL 450, Bench 12). Used for spatial tracking and production reconciliation.',
    `delay_code` STRING COMMENT 'The standardised delay classification code recorded when the fleet asset experienced a non-productive delay during the assignment (e.g., mechanical breakdown, waiting for blast, road block, operator break). Sourced from MineStar delay recording. [ENUM-REF-CANDIDATE: promote to reference product with delay_code and delay_description]',
    `delay_duration_minutes` STRING COMMENT 'The total duration in minutes of recorded delays experienced by the fleet asset during this assignment. Used in conjunction with delay_code for availability and utilisation analysis and OEE (Overall Equipment Effectiveness) reporting.',
    `destination_location_code` STRING COMMENT 'The mine location code identifying where material is being delivered (ROM pad, waste dump, crusher, stockpile, processing plant). Used for material tracking and haulage cycle analysis.',
    `dispatch_priority` STRING COMMENT 'Numeric priority ranking assigned by the MineStar dispatch system to determine the order in which fleet assets are assigned to tasks. Lower values indicate higher priority. Used for optimising fleet utilisation and meeting production targets.',
    `distance_travelled_km` DECIMAL(18,2) COMMENT 'The total distance in kilometres travelled by the mobile fleet asset during this assignment, sourced from MineStar GPS telematics. Used for haulage cycle analysis, tyre management, and maintenance scheduling.',
    `engine_hours` DECIMAL(18,2) COMMENT 'The number of engine operating hours accumulated by the fleet asset during this assignment, sourced from MineStar telematics. Used for maintenance scheduling, MTBF (Mean Time Between Failures) calculation, and asset lifecycle management.',
    `equipment_type` STRING COMMENT 'The category of mobile fleet equipment being assigned. Denormalised from the equipment master for operational reporting and dispatch efficiency. [ENUM-REF-CANDIDATE: haul_truck|drill|dozer|excavator|loader|grader|water_cart|conveyor|crusher — promote to reference product]',
    `fuel_consumed_litres` DECIMAL(18,2) COMMENT 'The actual volume of diesel fuel consumed in litres by the fleet asset during this assignment period, sourced from MineStar telematics or fuel management system. Used for OPEX (Operating Expenditure) tracking and fuel efficiency analysis.',
    `idle_time_minutes` STRING COMMENT 'The total number of minutes the fleet asset was in an idle state (engine running but not performing productive work) during this assignment. Used for OEE (Overall Equipment Effectiveness) analysis and identifying productivity improvement opportunities.',
    `is_planned_assignment` BOOLEAN COMMENT 'Indicates whether this fleet assignment was pre-planned in the mine production schedule (True) or was an ad-hoc/reactive dispatch by the shift supervisor (False). Used to measure schedule adherence and dispatch planning effectiveness.',
    `minestar_assignment_ref` STRING COMMENT 'The native assignment reference or dispatch ID from the Caterpillar MineStar Fleet Management System. Used for traceability and reconciliation back to the source system of record.',
    `payload_tonnes` DECIMAL(18,2) COMMENT 'The actual payload weight in metric tonnes carried or processed during this fleet assignment, as recorded by on-board payload monitoring systems. Applicable primarily to haul truck assignments. Used for production reconciliation and truck factor analysis.',
    `pit_name` STRING COMMENT 'The name or code of the open-cut pit or underground mine area to which the fleet asset is assigned. Provides operational context for dispatch and production reporting.',
    `planned_duration_minutes` STRING COMMENT 'The planned duration of the fleet assignment in minutes as per the mine production schedule or dispatch plan. Used to measure schedule adherence and identify variance between planned and actual assignment durations.',
    `planned_end_timestamp` TIMESTAMP COMMENT 'The originally scheduled end date and time for the fleet assignment as per the mine production schedule or dispatch plan. Used to measure schedule adherence.',
    `planned_start_timestamp` TIMESTAMP COMMENT 'The originally scheduled start date and time for the fleet assignment as per the mine production schedule or dispatch plan. Used to measure schedule adherence and dispatch efficiency.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The date and time when this fleet assignment record was first captured in the data platform. Used for data lineage, audit trail, and Silver layer ingestion tracking.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this fleet assignment record was last modified in the data platform. Used for change data capture, incremental processing, and audit trail in the Databricks Silver layer.',
    `shift_date` DATE COMMENT 'The calendar date of the shift during which this fleet assignment occurs. Used as the primary date dimension for daily production reporting and shift-based performance analysis.',
    `shift_type` STRING COMMENT 'The shift classification during which the fleet assignment is active. Typically day or night shift in a 12-hour rotation. Used for shift-based production reporting and OEE (Overall Equipment Effectiveness) analysis.. Valid values are `day|night|afternoon`',
    `source_location_code` STRING COMMENT 'The mine location code identifying where material is being loaded or work is being performed (dig face, blast block, stockpile). Used for material tracking and production reconciliation in MineStar.',
    `supervisor_notes` STRING COMMENT 'Free-text operational notes recorded by the shift supervisor regarding this fleet assignment, including any special instructions, safety observations, or operational exceptions. Sourced from MineStar dispatch comments.',
    `target_payload_tonnes` DECIMAL(18,2) COMMENT 'The target or design payload weight in metric tonnes for the fleet asset during this assignment, based on equipment specifications and mine planning targets. Used to measure payload efficiency and identify overloading or underloading.',
    `task_type` STRING COMMENT 'The primary operational task type assigned to the mobile fleet asset during this assignment. Classifies the nature of work being performed. [ENUM-REF-CANDIDATE: haulage|drilling|dozing|blasting_support|loading|grading|water_cart|ancillary — promote to reference product]',
    CONSTRAINT pk_fleet_assignment PRIMARY KEY(`fleet_assignment_id`)
) COMMENT 'Tracks the operational assignment of mobile fleet assets to specific mine areas, pits, benches, or processing circuits. Records assignment start and end dates, assigned shift, operating location, task type (haulage, drilling, dozing), and the responsible supervisor. Sourced from MineStar Fleet Management System.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`oee_record` (
    `oee_record_id` BIGINT COMMENT 'Unique surrogate identifier for each OEE composite metric record. Primary key for the oee_record data product in the equipment domain.',
    `asset_id` BIGINT COMMENT 'Reference to the mining fleet or fixed plant asset (e.g., haul truck, drill, shovel, crusher, conveyor) for which this OEE record is computed. Sourced from Infor EAM asset register and Caterpillar MineStar equipment master.',
    `cost_centre_id` BIGINT COMMENT 'Reference to the SAP cost centre responsible for this asset during the OEE period. Used for OPEX allocation and budget vs actual reporting against fleet performance.',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where the asset is deployed. Enables site-level OEE benchmarking and multi-site fleet performance comparison.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: OEE is measured against production schedule targets (throughput_target_t on oee_record derives from the schedule). Schedule vs actual OEE variance reporting is a core mine planning KPI. A mine planner',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: OEE targets and performance vary by product line in multi-product mining operations (iron ore lump vs fines circuits, different coal products). Production reporting and continuous improvement initiati',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Equipment OEE records for processing plant assets must be reconciled against the processing shift production run for the same period. This cross-domain reconciliation — matching equipment availability',
    `shift_report_id` BIGINT COMMENT 'Foreign key linking to mine.shift_report. Business justification: OEE records are generated per shift period and feed directly into shift report KPIs (equipment_utilisation_pct, equipment_operating_hours on shift_report). Mine supervisors reconcile OEE data against ',
    `specification_id` BIGINT COMMENT 'Foreign key linking to product.specification. Business justification: OEE quality_rate is measured against a product specification in processing plants. Without this FK, quality performance reporting cannot be tied to contractual or customer-specific specs. Mining plant',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: OEE metrics are tracked by tenement for performance reporting and expenditure commitment validation. Real mining operations report productivity by licence area to demonstrate compliance with minimum e',
    `actual_cycle_time_sec` DECIMAL(18,2) COMMENT 'The measured average time per production unit (e.g., haul cycle, crusher pass) achieved during the period. Compared against ideal_cycle_time_sec to derive Performance Rate. Sourced from MineStar dispatch and OSIsoft PI process historian.',
    `actual_operating_time_hrs` DECIMAL(18,2) COMMENT 'Actual hours the asset was in productive operation during the period, after deducting unplanned downtime and breakdowns. Core input to OEE Availability Rate calculation. Sourced from MineStar equipment health and OSIsoft PI historian.',
    `approved_by` STRING COMMENT 'Username or employee ID of the production supervisor or engineer who approved this OEE record in the reconciliation workflow. Supports audit trail requirements for OPEX reporting and regulatory compliance.',
    `availability_rate` DECIMAL(18,2) COMMENT 'The ratio of actual operating time to planned operating time, expressed as a decimal (e.g., 0.9250 = 92.50%). First component of the OEE composite metric. Calculated as actual_operating_time_hrs / planned_operating_time_hrs. Stored as a raw rate for precision; percentage display handled in reporting layer.',
    `comments` STRING COMMENT 'Free-text field for production supervisors or engineers to record contextual notes about this OEE record, such as reasons for low availability, abnormal operating conditions, or data quality caveats.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this OEE record was first created in the data platform, either by automated ingestion from MineStar/OSIsoft PI or by manual entry. Supports audit trail and data lineage.',
    `data_source` STRING COMMENT 'Identifies the primary operational system from which this OEE record was sourced or reconciled. Supports data lineage tracing and audit of production reconciliation processes.. Valid values are `minestar|osisoft_pi|infor_eam|manual|reconciliation`',
    `distance_travelled_km` DECIMAL(18,2) COMMENT 'Total distance travelled by mobile fleet assets (e.g., haul trucks, dozers) during the period, in kilometres. Used for tyre wear analysis, fuel efficiency benchmarking, and haul road condition assessment. Not applicable to fixed plant assets.',
    `engine_hours` DECIMAL(18,2) COMMENT 'Total engine running hours accumulated by the asset during the period. Used for maintenance scheduling, MTBF calculation, and asset lifecycle management in Infor EAM. Sourced from MineStar equipment health telematics.',
    `fuel_consumption_l` DECIMAL(18,2) COMMENT 'Total diesel fuel consumed by the asset during the period, measured in litres. Used for fuel efficiency analysis, OPEX cost allocation, and carbon emissions reporting. Sourced from MineStar fuel management or SAP MM fuel issue records.',
    `fuel_efficiency_t_per_l` DECIMAL(18,2) COMMENT 'Ratio of actual throughput in tonnes to fuel consumed in litres during the period. Key OPEX efficiency metric for haul trucks and mobile fleet. Enables benchmarking across fleet and identification of underperforming units.',
    `ideal_cycle_time_sec` DECIMAL(18,2) COMMENT 'The theoretical minimum time required to produce one unit (e.g., one haul cycle, one crusher pass) under optimal conditions. Used as the benchmark denominator in OEE Performance Rate calculation. Sourced from engineering design specifications or MineStar baseline models.',
    `is_reconciled` BOOLEAN COMMENT 'Indicates whether this OEE record has been through the production reconciliation process and validated against shift reports and source system data. Unreconciled records are provisional and should not be used for OPEX reporting.',
    `load_count` STRING COMMENT 'Total number of discrete load cycles (e.g., truck loads, shovel passes) completed by the asset during the period. Used for cycle time analysis and Performance Rate validation. Sourced from MineStar dispatch system.',
    `oee_rate` DECIMAL(18,2) COMMENT 'The composite OEE metric expressed as a decimal (e.g., 0.7500 = 75.00%), calculated as the multiplicative product of availability_rate × performance_rate × quality_rate. This is the primary KPI for fleet performance benchmarking, bottleneck identification, and OPEX reporting. Stored as a pre-reconciled rate from the production reconciliation system.',
    `oee_target_rate` DECIMAL(18,2) COMMENT 'The budgeted or contractually agreed OEE target rate for this asset type and period, expressed as a decimal. Used for variance analysis between actual OEE and planned OEE in OPEX reporting and fleet performance benchmarking.',
    `payload_avg_t` DECIMAL(18,2) COMMENT 'Average payload per load cycle in dry metric tonnes during the period. Used to assess truck loading efficiency against rated payload capacity. Sourced from MineStar payload monitoring system (VIMS/PLM).',
    `performance_rate` DECIMAL(18,2) COMMENT 'The ratio of actual production speed to ideal production speed during operating time, expressed as a decimal (e.g., 0.8750 = 87.50%). Second component of the OEE composite metric. Calculated as (ideal_cycle_time_sec × total_units_produced) / actual_operating_time_hrs. Stored as raw rate.',
    `period_end_timestamp` TIMESTAMP COMMENT 'The exact date and time marking the end of the production period for which OEE is calculated. Combined with period_start_timestamp to derive total period duration.',
    `period_start_timestamp` TIMESTAMP COMMENT 'The exact date and time marking the beginning of the production period (shift or sub-shift interval) for which OEE is calculated. Principal business event timestamp for this record. Sourced from MineStar shift dispatch or OSIsoft PI historian.',
    `planned_downtime_hrs` DECIMAL(18,2) COMMENT 'Total hours the asset was taken out of service for scheduled preventive maintenance, inspections, or planned shutdowns during the period. Excluded from planned operating time in OEE Availability calculation.',
    `planned_operating_time_hrs` DECIMAL(18,2) COMMENT 'Total scheduled hours the asset was planned to be in productive operation during the period, excluding planned maintenance windows and scheduled downtime. Core input to OEE Availability Rate calculation. Sourced from MineStar shift schedule.',
    `production_date` DATE COMMENT 'Calendar date associated with this OEE record, representing the production day. Used for daily and monthly OEE trend reporting and OPEX period alignment.',
    `quality_rate` DECIMAL(18,2) COMMENT 'The ratio of good units produced to total units produced, expressed as a decimal (e.g., 0.9900 = 99.00%). Third component of the OEE composite metric. Calculated as (total_units_produced - reject_unit_count) / total_units_produced. For mobile fleet assets where quality is not applicable, this defaults to 1.0000.',
    `reconciliation_timestamp` TIMESTAMP COMMENT 'Date and time when this OEE record was formally reconciled and approved in the production reconciliation system. Null if is_reconciled is false.',
    `record_number` STRING COMMENT 'Externally-known business identifier for this OEE record, formatted as OEE-YYYY-MM-NNNNNN. Used for cross-system referencing between MineStar, OSIsoft PI, and SAP PM reporting.. Valid values are `^OEE-[0-9]{4}-[0-9]{2}-[0-9]{6}$`',
    `record_status` STRING COMMENT 'Current lifecycle status of this OEE record within the production reconciliation workflow. Draft records are provisional; approved records are used for OPEX reporting and fleet benchmarking.. Valid values are `draft|pending_review|approved|rejected|superseded`',
    `reject_unit_count` BIGINT COMMENT 'Number of production units that did not meet quality specification during the period (e.g., crusher throughput below grade spec, off-spec concentrate batches). Core input to OEE Quality Rate calculation. Applicable primarily to fixed plant assets; set to zero for mobile fleet where quality is not directly measured.',
    `speed_avg_kmh` DECIMAL(18,2) COMMENT 'Average travel speed of the mobile asset during the period, in km/h. Used for haul road performance analysis, speed compliance monitoring, and Performance Rate benchmarking. Sourced from MineStar telematics.',
    `throughput_actual_t` DECIMAL(18,2) COMMENT 'Actual mass of material (ore or waste) processed or moved by the asset during the period, measured in dry metric tonnes. Primary quantitative production outcome for the period. Sourced from MineStar payload monitoring or OSIsoft PI belt scale historian.',
    `throughput_target_t` DECIMAL(18,2) COMMENT 'Planned or budgeted throughput in dry metric tonnes for this asset during the period. Used for production variance analysis and OEE Performance Rate benchmarking against mine plan.',
    `total_units_produced` BIGINT COMMENT 'Total count of production units (e.g., haul cycles completed, tonnes crushed, loads dispatched) achieved during the period. Used in Performance Rate and Quality Rate calculations. Sourced from MineStar dispatch or OSIsoft PI throughput counters.',
    `unplanned_downtime_hrs` DECIMAL(18,2) COMMENT 'Total hours the asset was unavailable due to unplanned breakdowns, mechanical failures, or unscheduled stoppages during the period. Key driver of Availability Rate degradation. Sourced from Infor EAM work order records.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this OEE record was most recently modified, including reconciliation updates, corrections, or status changes. Supports change tracking and data quality monitoring in the Silver layer.',
    CONSTRAINT pk_oee_record PRIMARY KEY(`oee_record_id`)
) COMMENT 'Periodic OEE (Overall Equipment Effectiveness) composite metric records capturing the multiplicative product of availability rate, performance rate, and quality rate for each asset per shift or production period. Distinct from utilisation_record which tracks raw time-based utilisation only. Includes planned operating time, actual operating time, ideal cycle time, total pieces produced, and reject count where applicable (e.g., crusher throughput vs spec). OEE percentage = Availability × Performance × Quality. Sourced from MineStar, OSIsoft PI, and production reconciliation systems. Used for fleet performance benchmarking, bottleneck identification, and OPEX reporting against budget.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`downtime_event` (
    `downtime_event_id` BIGINT COMMENT 'Unique surrogate identifier for each equipment downtime event record in the silver layer lakehouse. Primary key for this entity.',
    `asset_id` BIGINT COMMENT 'Reference to the specific piece of mining fleet or fixed plant equipment (e.g., haul truck, drill, shovel, conveyor) that experienced the downtime event. Sourced from Infor EAM asset register and Caterpillar MineStar.',
    `component_register_id` BIGINT COMMENT 'Foreign key linking to equipment.component_register. Business justification: Downtime events in mining are frequently caused by specific component failures (e.g., engine failure, hydraulic pump failure, tyre blowout). The downtime_event table currently stores component_code an',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Downtime events have direct cost implications (lost production, maintenance costs) that must be allocated to cost centres for variance analysis and cost performance reporting in mining operations.',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Downtime events are attributed to functional locations for bad-actor analysis and maintenance planning. downtime_event.functional_location_code is a denormalized text reference; a proper FK enables lo',
    `hazard_id` BIGINT COMMENT 'Foreign key linking to hse.hazard. Business justification: Downtime events caused by hazardous conditions (ground instability, electrical faults, gas detection) must reference the specific hazard for risk-based maintenance prioritisation, bow-tie analysis, an',
    `incident_id` BIGINT COMMENT 'Reference to the associated HSE incident record in IsoMetrix when is_safety_related is True. Links the downtime event to the formal safety investigation and regulatory reporting workflow. Null when no safety incident is associated.',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where the downtime event occurred (e.g., open pit, underground, processing plant).',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to mine.production_schedule. Business justification: Downtime events record production_tonnes_lost and production_impact_hours, which must be attributed to a production schedule period for schedule variance reporting and forecast updates. Mine planners ',
    `regulatory_condition_id` BIGINT COMMENT 'Foreign key linking to tenement.regulatory_condition. Business justification: Stop-work orders and compliance breaches (tenement regulatory conditions) directly cause equipment downtime. Mine compliance teams must link downtime events to the specific regulatory condition that t',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Production loss reporting requires knowing which saleable product was impacted by each downtime event. Fields production_tonnes_lost and production_impact_hours are meaningless without product context',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Regulatory production-loss reporting to mining authorities requires downtime events to be attributed to the specific tenement licence area affected. Mine compliance teams query downtime directly by te',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Downtime events on TSF-critical equipment (decant pumps, pipeline systems) must be attributed to the specific TSF for dam safety reporting, operational continuity tracking, and regulatory compliance. ',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Major repair and overhaul costs exceeding capitalisation thresholds are charged to WBS elements as CAPEX rather than OPEX. Downtime events triggering major component replacements must reference the WB',
    `work_order_id` BIGINT COMMENT 'Reference to the Infor EAM maintenance work order raised in response to or associated with this downtime event. Null for non-maintenance downtime categories such as weather or standby.',
    `actual_repair_hours` DECIMAL(18,2) COMMENT 'Actual number of labour hours expended to complete the repair or maintenance activity for this downtime event. Recorded upon event closure. Used to calculate Mean Time To Repair (MTTR) and to benchmark against estimated_repair_hours for continuous improvement.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this downtime event record was first created in the source system (Infor EAM or Caterpillar MineStar) and ingested into the silver layer. Used for audit trail, data lineage, and SLA compliance monitoring.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the maintenance_cost field (e.g., AUD, USD, ZAR). Supports multi-currency operations across international mine sites.. Valid values are `^[A-Z]{3}$`',
    `detection_method` STRING COMMENT 'Method by which the downtime event was first detected. Operator_report indicates the equipment operator raised the fault. SCADA_alarm indicates detection via OSIsoft PI System or PLC alarm. FMS_alert indicates detection via Caterpillar MineStar Fleet Management System. Condition_monitoring indicates detection via predictive maintenance sensors. Scheduled_inspection indicates detection during a planned inspection round. Third_party_report indicates detection reported by a contractor or external party.. Valid values are `operator_report|scada_alarm|fms_alert|condition_monitoring|scheduled_inspection|third_party_report`',
    `downtime_category` STRING COMMENT 'High-level classification of the downtime event type. Unplanned breakdown indicates an unexpected mechanical or electrical failure. Planned maintenance covers scheduled preventive or corrective maintenance windows. Standby covers equipment waiting for work assignment. Weather delay covers stoppages due to adverse environmental conditions. Operational delay covers delays caused by operational constraints such as blasting exclusion zones. Process delay covers upstream or downstream process bottlenecks.. Valid values are `unplanned_breakdown|planned_maintenance|standby|weather_delay|operational_delay|process_delay`',
    `downtime_reason_code` STRING COMMENT 'Standardised reason code identifying the specific cause of the downtime event (e.g., engine failure, tyre change, hydraulic leak, conveyor belt tear, electrical fault). Sourced from Infor EAM failure code library and Caterpillar MineStar reason code catalogue. [ENUM-REF-CANDIDATE: engine_failure|tyre_change|hydraulic_leak|conveyor_belt_tear|electrical_fault|structural_damage|operator_error|fuel_system|cooling_system|brake_system — promote to reference product]',
    `downtime_status` STRING COMMENT 'Current lifecycle status of the downtime event record. Open indicates the event has been logged but resolution has not commenced. In_progress indicates maintenance or corrective action is underway. Resolved indicates the equipment has been returned to service. Cancelled indicates the event was logged in error. Pending_approval indicates the event record is awaiting supervisory sign-off.. Valid values are `open|in_progress|resolved|cancelled|pending_approval`',
    `duration_minutes` STRING COMMENT 'Total elapsed duration of the downtime event expressed in whole minutes, calculated as the difference between end_timestamp and start_timestamp. Stored as a business field to support direct reporting and MTTR calculations without requiring timestamp arithmetic at query time. Null if end_timestamp is not yet recorded.',
    `end_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) at which the equipment was returned to operational service and the downtime event concluded. Null if the event is still open or in progress. Used in conjunction with start_timestamp to calculate actual downtime duration.',
    `environmental_impact_flag` BOOLEAN COMMENT 'Indicates whether this downtime event resulted in or had the potential to cause an environmental impact (e.g., hydraulic fluid spill, dust emission exceedance, tailings pump failure). True triggers environmental notification and reporting obligations under ISO 14001 and site Environmental Impact Statement (EIS) conditions.',
    `estimated_repair_hours` DECIMAL(18,2) COMMENT 'Estimated number of labour hours required to complete the repair or maintenance activity associated with this downtime event, as assessed at the time of event creation. Used for maintenance scheduling, resource planning, and comparison against actual repair duration to improve future estimates.',
    `event_description` STRING COMMENT 'Free-text narrative description of the downtime event as recorded by the operator or maintenance technician at the time of reporting. Captures contextual details not covered by structured fields, including observed symptoms, environmental conditions, and initial diagnosis. Sourced from Infor EAM notification text or Caterpillar MineStar operator notes.',
    `event_number` STRING COMMENT 'Externally-known business identifier for the downtime event, formatted as DT-YYYY-NNNNNN. Used for cross-referencing with Infor EAM work orders, MineStar dispatch logs, and SAP PM notifications. Supports traceability across operational systems.. Valid values are `^DT-[0-9]{4}-[0-9]{6}$`',
    `failure_mode` STRING COMMENT 'Describes the specific manner in which the equipment failed or the mechanism of the downtime (e.g., fatigue fracture, corrosion, overheating, wear, contamination, misalignment). Aligned with ISO 14224 failure mode taxonomy and used in Reliability Centred Maintenance (RCM) analysis. [ENUM-REF-CANDIDATE: fatigue_fracture|corrosion|overheating|wear|contamination|misalignment|vibration|leakage|blockage|electrical_short — promote to reference product]',
    `is_safety_related` BOOLEAN COMMENT 'Indicates whether this downtime event was caused by or resulted in a safety incident, near-miss, or equipment condition that posed a risk to personnel. True triggers mandatory notification to the Health, Safety and Environment (HSE) team and may require IsoMetrix incident reporting. Supports Lost Time Injury Frequency Rate (LTIFR) and Total Recordable Injury Frequency Rate (TRIFR) compliance reporting.',
    `maintenance_cost` DECIMAL(18,2) COMMENT 'Total direct cost incurred to resolve this downtime event, including labour, parts, and consumables as captured in Infor EAM and SAP S/4HANA CO. Expressed in the site operating currency. Used for Operating Expenditure (OPEX) tracking, cost-per-hour analysis, and maintenance budget variance reporting.',
    `maintenance_type` STRING COMMENT 'Classification of the maintenance activity associated with this downtime event. Corrective maintenance addresses failures after they occur. Preventive maintenance is time-based scheduled work. Predictive maintenance is triggered by condition monitoring data. Condition-based maintenance is triggered by measured parameter thresholds. Emergency maintenance addresses safety-critical failures requiring immediate response. Null for non-maintenance downtime categories.. Valid values are `corrective|preventive|predictive|condition_based|emergency`',
    `oee_impact_category` STRING COMMENT 'Classification of how this downtime event impacts the Overall Equipment Effectiveness (OEE) calculation. Availability losses arise from unplanned breakdowns and planned maintenance. Performance losses arise from reduced speed or throughput. Quality losses arise from off-spec production. Used to decompose OEE into its three constituent factors for targeted improvement initiatives.. Valid values are `availability|performance|quality`',
    `priority_level` STRING COMMENT 'Priority classification assigned to the downtime event to drive maintenance resource allocation and response urgency. Critical indicates immediate safety or production-stopping impact. High indicates significant production impact requiring same-shift response. Medium indicates moderate impact with next-shift response acceptable. Low indicates minor impact with scheduled response acceptable.. Valid values are `critical|high|medium|low`',
    `production_impact_hours` DECIMAL(18,2) COMMENT 'Estimated or actual number of production hours lost as a direct consequence of this downtime event. Accounts for the impact on the production schedule and is used to quantify the effect on Overall Equipment Effectiveness (OEE) and Life of Mine (LOM) plan adherence. Sourced from Caterpillar MineStar productivity tracking.',
    `production_tonnes_lost` DECIMAL(18,2) COMMENT 'Estimated tonnage of ore or material (Run of Mine — ROM) that was not moved or processed as a direct result of this downtime event. Used to quantify the financial and operational impact of equipment unavailability on the mine production schedule.',
    `resolution_notes` STRING COMMENT 'Free-text description of the corrective actions taken to resolve the downtime event and return the equipment to service. Recorded by the maintenance technician upon event closure. Supports knowledge management, recurring fault analysis, and Standard Operating Procedure (SOP) improvement.',
    `return_to_service_timestamp` TIMESTAMP COMMENT 'The precise date and time at which the equipment was formally cleared and returned to operational service following resolution of the downtime event. May differ from end_timestamp if post-repair inspection or commissioning steps are required before the equipment is released to operations.',
    `root_cause_analysis_status` STRING COMMENT 'Status of the formal Root Cause Analysis (RCA) investigation for this downtime event. Not_required for minor or routine events. Pending indicates RCA has been triggered but not yet commenced. In_progress indicates investigation is underway. Completed indicates findings have been documented and corrective actions assigned. Mandatory for critical and high-priority events per site maintenance governance standards.. Valid values are `not_required|pending|in_progress|completed`',
    `shift_type` STRING COMMENT 'Classification of the shift during which the downtime event commenced (day, afternoon, or night). Stored directly on the event to support shift-level reporting without requiring a join to the shift master when shift_id is unavailable.. Valid values are `day|afternoon|night`',
    `start_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) at which the equipment became unavailable or the downtime event commenced. This is the principal real-world event time used for Mean Time Between Failures (MTBF) and Mean Time To Repair (MTTR) calculations. Sourced from Caterpillar MineStar or OSIsoft PI System historian.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this downtime event record was most recently modified in the source system or silver layer. Used for change data capture, incremental load processing, and audit trail compliance.',
    CONSTRAINT pk_downtime_event PRIMARY KEY(`downtime_event_id`)
) COMMENT 'Records each individual equipment downtime event including unplanned breakdowns, planned maintenance windows, standby, and weather delays. Captures start and end timestamps, downtime category, downtime reason code, responsible crew, and impact on production. Used to calculate MTBF and MTTR and to drive maintenance prioritisation.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`telemetry_event` (
    `telemetry_event_id` BIGINT COMMENT 'Primary key for telemetry_event',
    `asset_id` BIGINT COMMENT 'Reference to the master equipment or fleet asset record that generated this telemetry event. Links to the equipment master register in the Equipment domain.',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Geofence breaches, overspeed events, and fault codes in telemetry directly trigger HSE incidents. Post-incident investigation requires linking the triggering telemetry event to the incident record for',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where the equipment was operating when this telemetry event was captured.',
    `tsf_id` BIGINT COMMENT 'Reference to the geofence zone in which the equipment was located at the time of the telemetry event. Used for geofence compliance monitoring, blast exclusion zone enforcement, and haulage route adherence.',
    `waste_rock_dump_id` BIGINT COMMENT 'Foreign key linking to tailings.waste_rock_dump. Business justification: Telemetry from equipment operating at waste rock dumps (dozers, compactors, haul trucks) requires WRD attribution for geofence compliance monitoring, operational reporting, and environmental boundary ',
    `ambient_temperature_c` DECIMAL(18,2) COMMENT 'Ambient air temperature in degrees Celsius recorded by the equipments external temperature sensor at the time of the telemetry event. Used for equipment performance normalisation and heat stress risk assessment under ISO 45001.',
    `battery_voltage_v` DECIMAL(18,2) COMMENT 'Onboard electrical system battery voltage in volts at the time of the telemetry event. Low voltage readings indicate potential electrical system faults and are used to trigger preventive maintenance actions in Infor EAM.',
    `brake_applied` BOOLEAN COMMENT 'Indicates whether the service brake was applied at the time of the telemetry event. Used for operator behaviour analysis, brake wear monitoring, and safety compliance reporting under ISO 45001.',
    `coolant_temperature_c` DECIMAL(18,2) COMMENT 'Engine coolant temperature in degrees Celsius at the time of the telemetry event. A critical health indicator; values exceeding thresholds trigger predictive maintenance alerts and potential equipment shutdown.',
    `data_quality_flag` STRING COMMENT 'Quality assessment flag applied during silver layer processing to indicate the reliability of this telemetry record. Suspect or invalid records may result from sensor malfunction, communication dropout, or out-of-range values. Used to filter records in analytics and predictive maintenance models.. Valid values are `valid|suspect|invalid|interpolated`',
    `elevation_m` DECIMAL(18,2) COMMENT 'Altitude of the equipment above mean sea level in metres at the time of the telemetry event. Used for bench-level positioning, grade resistance calculations, and mine design alignment.',
    `engine_hours` DECIMAL(18,2) COMMENT 'Cumulative engine operating hours recorded on the equipment odometer at the time of this telemetry event. Primary driver for preventive maintenance scheduling and Mean Time Between Failures (MTBF) calculations in Infor EAM.',
    `engine_load_pct` DECIMAL(18,2) COMMENT 'Engine load as a percentage of maximum rated capacity at the time of the telemetry event. Indicates whether the equipment is operating within design parameters. Used for OEE and fuel consumption analysis.',
    `engine_rpm` STRING COMMENT 'Instantaneous engine speed in revolutions per minute at the time of the telemetry event. Used for engine load analysis, fuel efficiency monitoring, and predictive maintenance trigger detection.',
    `equipment_status` STRING COMMENT 'The operational state of the equipment at the moment of this telemetry event as reported by the Fleet Management System (FMS). Supports Overall Equipment Effectiveness (OEE) and utilisation calculations. [ENUM-REF-CANDIDATE: operating|idle|standby|down|tramming|loading|dumping — promote to reference product]',
    `event_timestamp` TIMESTAMP COMMENT 'The precise date and time (UTC) at which the sensor snapshot or event trigger was recorded by the onboard telematics system. Sub-minute frequency. This is the principal real-world event time, distinct from ingestion audit timestamps.',
    `event_type` STRING COMMENT 'Discriminator classifying the nature of the telemetry event. Periodic snapshots are time-driven; threshold breach, engine, geofence, payload, and fault code events are trigger-driven. [ENUM-REF-CANDIDATE: periodic_snapshot|threshold_breach|engine_event|geofence_event|payload_event|fault_code_event — promote to reference product]. Valid values are `periodic_snapshot|threshold_breach|engine_event|geofence_event|payload_event|fault_code_event`',
    `fault_code` STRING COMMENT 'Diagnostic fault or alarm code generated by the equipments onboard diagnostic system (OBD/J1939) at the time of the event. Null for periodic snapshots with no active fault. Used to trigger work orders in Infor EAM and predictive maintenance workflows.',
    `fault_severity` STRING COMMENT 'Severity classification of the fault code raised at the time of this telemetry event. Critical and high severity faults may trigger immediate equipment shutdown or dispatch of maintenance crew. Null when no fault is active.. Valid values are `critical|high|medium|low|informational`',
    `fuel_consumption_rate_lph` DECIMAL(18,2) COMMENT 'Instantaneous fuel burn rate in litres per hour as reported by the onboard fuel flow sensor at the time of the telemetry event. Used for OPEX (Operating Expenditure) monitoring and All-In Sustaining Cost (AISC) calculations.',
    `fuel_level_pct` DECIMAL(18,2) COMMENT 'Current fuel tank level expressed as a percentage of total tank capacity at the time of the telemetry event. Used for fuel management, dispatch planning, and refuelling schedule optimisation. Distinct from discrete fuel dispensing events recorded in fuel_consumption.',
    `geofence_breach` BOOLEAN COMMENT 'Indicates whether the equipment was in breach of an active geofence boundary at the time of this telemetry event. True when the equipment has entered a restricted or exclusion zone without authorisation. Supports safety compliance and HSE reporting.',
    `heading_degrees` DECIMAL(18,2) COMMENT 'Compass bearing of the equipment direction of travel in degrees (0–360) at the time of the telemetry event. Used for directional analysis and geofence zone entry/exit detection.',
    `hydraulic_pressure_kpa` DECIMAL(18,2) COMMENT 'Hydraulic system pressure in kilopascals at the time of the telemetry event. Used for monitoring hydraulic system health on shovels, drills, and haul trucks. Anomalies indicate potential hydraulic failure.',
    `ingested_timestamp` TIMESTAMP COMMENT 'The date and time at which this telemetry record was received and loaded into the lakehouse silver layer from the source system (MineStar, Wenco, Modular Mining, or OSIsoft PI). Used for data latency monitoring and pipeline audit.',
    `latitude` DOUBLE COMMENT 'WGS84 decimal degrees latitude of the equipment position at the time of the telemetry event. Sourced from onboard GPS unit. Used for geofence compliance, haulage route analysis, and GIS integration.',
    `longitude` DOUBLE COMMENT 'WGS84 decimal degrees longitude of the equipment position at the time of the telemetry event. Sourced from onboard GPS unit. Used for geofence compliance, haulage route analysis, and GIS integration.',
    `odometer_km` DECIMAL(18,2) COMMENT 'Cumulative distance travelled by the equipment in kilometres as recorded on the onboard odometer at the time of the telemetry event. Used for tyre life management, component replacement scheduling, and haulage distance reporting.',
    `payload_weight_t` DECIMAL(18,2) COMMENT 'Instantaneous payload weight in metric tonnes as measured by the onboard payload monitoring system at the time of the telemetry event. Used for haulage productivity analysis, truck factor compliance, and ROM (Run of Mine) tonnage tracking.',
    `signal_quality` STRING COMMENT 'Quality classification of the wireless or satellite communication signal at the time the telemetry event was transmitted. Used to assess data reliability and identify underground or remote areas with poor connectivity.. Valid values are `excellent|good|fair|poor|no_signal`',
    `source_system` STRING COMMENT 'The originating operational system or IoT integration platform that produced this telemetry event record. Supports data lineage and multi-source reconciliation across MineStar, Wenco, Modular Mining, and OSIsoft PI.. Valid values are `MineStar|Wenco|Modular Mining|OSIsoft PI|SCADA`',
    `speed_kmh` DECIMAL(18,2) COMMENT 'Instantaneous travel speed of the equipment in kilometres per hour at the time of the telemetry event. Used for speed limit compliance monitoring, operator behaviour analysis, and haulage cycle time analysis.',
    `transmission_gear` STRING COMMENT 'Current transmission gear position of the equipment at the time of the telemetry event. Used for operator behaviour analysis, ramp grade compliance, and drivetrain health monitoring.',
    `tyre_pressure_front_left_kpa` DECIMAL(18,2) COMMENT 'Tyre pressure of the front-left tyre in kilopascals at the time of the telemetry event. Tyre pressure monitoring is critical for haul truck safety and tyre life management on large mining vehicles.',
    `tyre_pressure_front_right_kpa` DECIMAL(18,2) COMMENT 'Tyre pressure of the front-right tyre in kilopascals at the time of the telemetry event. Tyre pressure monitoring is critical for haul truck safety and tyre life management on large mining vehicles.',
    `tyre_pressure_rear_left_kpa` DECIMAL(18,2) COMMENT 'Tyre pressure of the rear-left tyre in kilopascals at the time of the telemetry event. Rear tyres on haul trucks carry the majority of loaded payload weight and are subject to higher wear and failure risk.',
    `tyre_pressure_rear_right_kpa` DECIMAL(18,2) COMMENT 'Tyre pressure of the rear-right tyre in kilopascals at the time of the telemetry event. Rear tyres on haul trucks carry the majority of loaded payload weight and are subject to higher wear and failure risk.',
    CONSTRAINT pk_telemetry_event PRIMARY KEY(`telemetry_event_id`)
) COMMENT 'High-frequency telemetry and sensor readings from onboard equipment systems including GPS position, engine hours, speed, payload weight, tyre pressure, hydraulic pressure, fuel level, coolant temperature, and engine RPM. Each record represents a single sensor snapshot or event trigger at sub-minute frequency. Sourced from MineStar, Wenco, Modular Mining, and OSIsoft PI System via SCADA/IoT integration. Supports real-time equipment health monitoring, geofence compliance, predictive maintenance trigger detection, and operator behaviour analysis. Distinct from fuel_consumption which records discrete dispensing events at much lower frequency.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`fuel_consumption` (
    `fuel_consumption_id` BIGINT COMMENT 'Unique surrogate identifier for each fuel dispensing event or shift-end fuel measurement record in the silver layer lakehouse.',
    `cost_centre_id` BIGINT COMMENT 'Reference to the SAP cost centre to which the fuel cost is allocated. Supports OPEX cost allocation to fleet and C1 cash cost per tonne reporting.',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Fuel spills during dispensing are reportable environmental incidents. Fuel transactions involved in spills, overfills, or contamination events must link to the incident record for regulatory reporting',
    `mine_site_id` BIGINT COMMENT 'Foreign key linking to mine.mine_site. Business justification: Fuel consumption is tracked per mine site for GHG emissions reporting, fuel budget management, and cost allocation. mine_site_code is a denormalized plain-text representation of mine_site. A mining op',
    `asset_id` BIGINT COMMENT 'Reference to the mining fleet or fixed plant asset (haul truck, drill, shovel, dozer, etc.) that consumed the fuel. Links to the equipment master register in the equipment domain.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Fuel transactions reference bulk fuel purchase orders (contracts with fuel suppliers); linking enables reconciliation of dispensed fuel against contracted supply, invoice verification, and fuel cost a',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to procurement.material_master. Business justification: Fuel is a procured material managed in the material master (fuel type, unit cost, storage conditions, hazard class). This link enables fuel cost reconciliation against procurement pricing, inventory b',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Fuel costs are a primary component of tenement minimum expenditure commitment obligations under mining licences. Tenement compliance teams allocate fuel expenditure to specific tenements for statutory',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Fuel consumed during capital development projects (mine construction, infrastructure) is capitalized and tracked against WBS elements for project cost control and capitalization accounting.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to maintenance.work_order. Business justification: Fuel issued during maintenance tasks is recorded against work orders in EAM systems for cost capture and AISC allocation. fuel_consumption.work_order_number is a denormalized text reference to mainten',
    `anomaly_reason` STRING COMMENT 'Free-text or coded description of the reason the transaction was flagged as an anomaly (e.g., Quantity exceeds tank capacity, Location outside mine boundary, Duplicate transaction within 30 minutes). Populated only when is_anomaly_flagged is True.',
    `authorised_by` STRING COMMENT 'Name or employee ID of the supervisor or fuel controller who authorised the dispensing event. Required for fuel theft detection controls and audit compliance.',
    `co2e_emissions_kg` DECIMAL(18,2) COMMENT 'Calculated Scope 1 greenhouse gas emissions in kilograms of CO2 equivalent for this fuel consumption event, derived by applying the applicable emissions factor for the fuel type to the quantity dispensed. Used for GRI and ICMM carbon reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this fuel consumption record was first created in the silver layer lakehouse. Used for data lineage, audit trail, and SLA monitoring of data pipeline latency.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the fuel cost amounts (e.g., AUD, USD, ZAR). Required for multi-jurisdiction mining operations where fuel is procured in different currencies.. Valid values are `^[A-Z]{3}$`',
    `dispensing_location_code` BIGINT COMMENT 'Reference to the physical location where fuel was dispensed (fuel bay, ROM pad field refuelling point, tank farm). Links to the site location master.',
    `dispensing_method` STRING COMMENT 'Physical method by which fuel was delivered to the asset: fixed_bay (permanent fuel bay infrastructure), bowser (mobile tank truck field refuelling), drum (manual drum dispensing for remote equipment), or pipeline (direct pipeline connection at processing plant).. Valid values are `fixed_bay|bowser|drum|pipeline`',
    `emissions_factor_kg_per_litre` DECIMAL(18,2) COMMENT 'The greenhouse gas emissions factor applied to this transaction, in kg CO2e per litre, specific to the fuel type. Captured at transaction time to preserve the factor version used for regulatory reporting and audit purposes.',
    `engine_hours_at_fill` DECIMAL(18,2) COMMENT 'Cumulative engine hours recorded on the asset at the time of the fuelling event. Used to calculate fuel consumption per engine hour, track MTBF intervals, and schedule preventive maintenance in Infor EAM.',
    `fuel_burn_rate_l_per_hr` DECIMAL(18,2) COMMENT 'Instantaneous or average fuel consumption rate in litres per engine hour at the time of the fuelling event or measurement period. Sourced from MineStar telematics. Used for OEE analysis and fleet fuel efficiency benchmarking.',
    `fuel_docket_number` STRING COMMENT 'Physical or electronic docket/receipt number issued at the point of dispensing. Used for three-way reconciliation between FMS records, physical dockets, and SAP purchase orders.',
    `fuel_type` STRING COMMENT 'Type of fuel dispensed: diesel (standard ultra-low sulphur diesel), LNG (liquefied natural gas for LNG-powered haul trucks), biodiesel B20 blend (20% biodiesel), biodiesel B100 (pure biodiesel), or HVO (hydrotreated vegetable oil). Drives emissions factor selection for Scope 1 carbon accounting.. Valid values are `diesel|lng|biodiesel_b20|biodiesel_b100|hvo`',
    `gps_latitude` DECIMAL(18,2) COMMENT 'WGS84 decimal latitude of the fuelling event location as recorded by MineStar telematics or the FMS. Used for GIS-based fuel consumption heat mapping and field refuelling route optimisation.',
    `gps_longitude` DECIMAL(18,2) COMMENT 'WGS84 decimal longitude of the fuelling event location as recorded by MineStar telematics or the FMS. Used in conjunction with gps_latitude for spatial analysis of fuel consumption patterns.',
    `is_anomaly_flagged` BOOLEAN COMMENT 'Boolean flag set to True when the fuel transaction has been identified as a potential anomaly by automated detection rules (e.g., quantity dispensed exceeds tank capacity, fill rate outside normal range, location mismatch). Triggers investigation workflow for fuel theft detection.',
    `odometer_km_at_fill` DECIMAL(18,2) COMMENT 'Cumulative distance travelled in kilometres recorded on the asset at the time of the fuelling event. Applicable to mobile fleet (haul trucks, light vehicles). Null for fixed plant or tracked equipment without odometers.',
    `quantity_dispensed_litres` DECIMAL(18,2) COMMENT 'Volume of fuel dispensed during this transaction, measured in litres to three decimal places. The primary quantitative fact for OPEX cost allocation, C1 cash cost per tonne calculation, and Scope 1 emissions accounting.',
    `source_record_code` STRING COMMENT 'The native primary key or transaction identifier from the originating source system (MineStar, FMS, PI System, or Infor EAM). Retained for data lineage, deduplication, and reconciliation back to the system of record.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this fuel consumption record was ingested: MineStar Fleet Management, a standalone Fuel Management System (FMS), OSIsoft PI System SCADA, Infor EAM, or manual entry. Used for data lineage and reconciliation.. Valid values are `minestar|fms|scada_pi|infor_eam|manual`',
    `tank_capacity_litres` DECIMAL(18,2) COMMENT 'Maximum rated fuel tank capacity of the asset in litres. Used to calculate fill percentage and validate that dispensed quantity does not exceed physical tank capacity.',
    `tank_level_after_litres` DECIMAL(18,2) COMMENT 'Fuel level in the assets onboard tank immediately after the dispensing event, in litres. Used with tank_level_before_litres to validate dispensed quantity and detect discrepancies indicative of fuel theft.',
    `tank_level_before_litres` DECIMAL(18,2) COMMENT 'Fuel level in the assets onboard tank immediately before the dispensing event, in litres. Used with tank_level_after_litres to validate dispensed quantity and detect fuel theft or leakage anomalies.',
    `total_fuel_cost` DECIMAL(18,2) COMMENT 'Total monetary cost of fuel dispensed in this transaction (quantity_dispensed_litres × unit_cost_per_litre), in the site operating currency. Used for OPEX cost allocation to fleet and C1 cash cost per tonne reporting. Note: this is a transaction-level cost capture, not a derived aggregate.',
    `transaction_number` STRING COMMENT 'Externally-known unique reference number assigned by the Fuel Management System (FMS) or MineStar to identify this dispensing event or measurement. Used for reconciliation with source systems and audit trails.',
    `transaction_status` STRING COMMENT 'Current workflow state of the fuel transaction record. Confirmed transactions are included in OPEX and emissions reporting. Voided or disputed records are excluded from cost allocation until resolved.. Valid values are `confirmed|pending|voided|disputed|under_review`',
    `transaction_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) at which the fuel dispensing event commenced or the shift-end measurement was recorded. This is the principal real-world event time used for time-series analysis and Scope 1 emissions accounting.',
    `transaction_type` STRING COMMENT 'Classifies the nature of the fuel record: a discrete refuelling event at a fuel bay (refuel), a periodic shift-end fuel measurement (shift_measurement), a manual tank dip reading (tank_dip), a field refuelling by bowser (field_refuel), or a bulk fuel transfer between storage tanks (bulk_transfer).. Valid values are `refuel|shift_measurement|tank_dip|field_refuel|bulk_transfer`',
    `unit_cost_per_litre` DECIMAL(18,2) COMMENT 'Contracted or spot price paid per litre of fuel at the time of the transaction, in the site operating currency. Confidential commercial pricing data. Used for OPEX cost allocation and C1 cash cost per tonne calculation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this fuel consumption record in the silver layer. Tracks corrections, status changes, and anomaly flag updates for audit compliance.',
    CONSTRAINT pk_fuel_consumption PRIMARY KEY(`fuel_consumption_id`)
) COMMENT 'Records discrete fuel dispensing events and periodic fuel usage measurements per asset. Each record represents a single refuelling transaction or shift-end fuel measurement. Captures fuel type (diesel, LNG, biodiesel blend), quantity dispensed in litres, fuel burn rate (L/hr), odometer or engine hours at fill, dispensing location (fuel bay, field refuelling), tank truck ID, and operator. Sourced from MineStar, Fuel Management Systems (FMS), and tank farm SCADA. Used for OPEX cost allocation to fleet, C1 cash cost per tonne reporting, carbon emissions accounting (Scope 1), and fuel theft detection.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`utilisation_record` (
    `utilisation_record_id` BIGINT COMMENT 'Unique surrogate identifier for each shift-level or daily utilisation record. Primary key for the utilisation_record data product in the equipment domain.',
    `area_id` BIGINT COMMENT 'Foreign key linking to mine.mine_area. Business justification: Equipment utilisation by mine area (pit, underground level, waste dump) is a standard fleet management KPI used for area-level productivity analysis and equipment allocation decisions. operating_zone ',
    `asset_id` BIGINT COMMENT 'Reference to the mining fleet or fixed plant asset (e.g., haul truck, drill, shovel, conveyor) for which this utilisation record applies. Sourced from Infor EAM asset register.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Equipment utilization hours drive cost allocation to cost centres for mining cost accounting, unit cost calculation, and AISC reporting. Essential for cost per tonne analysis.',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: HSE incidents cause equipment downtime captured in utilisation records. Mining KPI reporting (LTIFR, production loss attribution) requires linking utilisation downtime hours to the causative incident ',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where the asset was deployed during this utilisation period.',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Equipment utilisation is tracked per product campaign in multi-product mining operations. Asset performance reporting and production planning require product-segmented utilisation analysis to optimize',
    `shift_production_run_id` BIGINT COMMENT 'Foreign key linking to processing.shift_production_run. Business justification: Equipment utilisation records for processing plant assets are generated in the context of a specific processing shift production run. Linking them enables integrated shift performance reporting — reco',
    `shift_report_id` BIGINT COMMENT 'Foreign key linking to mine.shift_report. Business justification: Equipment utilisation records are reconciled against shift reports for shift-level KPI reporting (equipment hours vs ore mined). shift_report_reference is a denormalized plain-text column. Mine planne',
    `shutdown_plan_id` BIGINT COMMENT 'Foreign key linking to maintenance.shutdown_plan. Business justification: Fleet utilisation reporting directly references shutdown plans: planned_maintenance_hours and scheduled_hours in utilisation records are attributed to specific shutdown plans. Mining operations track ',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Utilisation records feed tenement minimum expenditure commitment reporting — mining licences require proof of equipment hours worked on the tenement. Tenement managers reconcile utilisation hours agai',
    `volume_plan_id` BIGINT COMMENT 'Foreign key linking to sales.volume_plan. Business justification: Equipment-constrained volume planning: mine planners link utilisation records (physical availability %, utilisation %) directly to volume plans to validate achievable sales volumes. Actual fleet utili',
    `approved_by` STRING COMMENT 'Name or employee identifier of the shift supervisor or production controller who approved this utilisation record after reconciliation. Provides accountability for official production reporting.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the utilisation record was formally approved by the shift supervisor or production controller. Marks the record as authoritative for inclusion in production and fleet performance reports.',
    `comments` STRING COMMENT 'Free-text field for shift supervisor or production controller notes explaining anomalies, reconciliation adjustments, or contextual information about the utilisation record (e.g., blast delay reason, equipment swap details).',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this utilisation record was first created in the source system (MineStar FMS or manual entry). Audit trail field for data lineage and reconciliation tracking.',
    `cycle_count` STRING COMMENT 'Number of complete operational cycles (e.g., load-haul-dump cycles for trucks, drill-hole completions for drills) performed by the asset during the period. Used for productivity rate analysis and equipment wear modelling.',
    `data_source` STRING COMMENT 'System or method from which this utilisation record was sourced (e.g., MineStar FMS automated telemetry, manual shift report entry, SCADA, OSIsoft PI System). Supports data lineage and quality assessment.. Valid values are `minestar|manual|scada|pi_system|inefor_eam`',
    `delay_hours` DECIMAL(18,2) COMMENT 'Hours lost to operational delays not attributable to maintenance (e.g., blast delays, traffic management, shift change, fuelling, operator fatigue breaks). Captured separately to support delay category analysis.',
    `distance_travelled_km` DECIMAL(18,2) COMMENT 'Total distance travelled by the asset during the utilisation period in kilometres, sourced from MineStar GPS telematics. Used for tyre life management, road condition analysis, and haulage productivity benchmarking.',
    `downtime_hours` DECIMAL(18,2) COMMENT 'Total hours the asset was unavailable for production due to planned or unplanned maintenance, breakdowns, or inspections. Used in MTBF and MTTR calculations and physical availability reporting.',
    `engine_hours` DECIMAL(18,2) COMMENT 'Total engine-on hours recorded by the assets onboard telematics during the period. Used for maintenance scheduling, component life tracking, and MTBF (Mean Time Between Failures) calculations in Infor EAM.',
    `fuel_burn_rate_lph` DECIMAL(18,2) COMMENT 'Average fuel consumption rate in litres per operating hour during the period. Benchmarked against OEM specifications to identify engine inefficiency, overloading, or operator behaviour issues.',
    `fuel_consumed_litres` DECIMAL(18,2) COMMENT 'Total volume of diesel or other fuel consumed by the asset during the utilisation period, measured in litres. Used for OPEX (Operating Expenditure) tracking, fuel burn rate benchmarking, and emissions reporting.',
    `idle_hours` DECIMAL(18,2) COMMENT 'Hours the asset was powered on and available but not performing productive work (e.g., waiting for trucks, queuing at crusher). Key metric for identifying operational inefficiencies and fleet sizing opportunities.',
    `is_reconciled` BOOLEAN COMMENT 'Indicates whether this utilisation record has been reconciled against the corresponding shift report. Unreconciled records are flagged for review before inclusion in official production reporting.',
    `oee_score` DECIMAL(18,2) COMMENT 'Composite OEE (Overall Equipment Effectiveness) score for the asset during the period, expressed as a percentage. Combines availability, performance, and quality dimensions. Sourced from MineStar or calculated during silver layer processing.',
    `operating_hours` DECIMAL(18,2) COMMENT 'Actual hours the asset was actively engaged in productive work (e.g., hauling, drilling, loading) during the period. Core numerator for utilisation percentage calculation.',
    `payload_tonnes` DECIMAL(18,2) COMMENT 'Total material payload moved by the asset during the utilisation period in dry metric tonnes. Applicable to haul trucks and loaders. Key productivity metric for ROM (Run of Mine) material movement tracking.',
    `period_end_timestamp` TIMESTAMP COMMENT 'Exact date and time marking the end of the utilisation measurement period (shift end or day end). Used with period_start_timestamp to validate that hours components sum correctly.',
    `period_start_timestamp` TIMESTAMP COMMENT 'Exact date and time marking the beginning of the utilisation measurement period (shift start or day start). Conforms to ISO 8601 with timezone offset for multi-timezone mine operations.',
    `physical_availability_pct` DECIMAL(18,2) COMMENT 'Percentage of scheduled hours during which the asset was mechanically available (not in maintenance downtime). Calculated as ((scheduled_hours - downtime_hours) / scheduled_hours) * 100. Distinct from utilisation — measures mechanical readiness.',
    `planned_maintenance_hours` DECIMAL(18,2) COMMENT 'Hours the asset was unavailable due to scheduled preventive maintenance activities. Subset of downtime_hours. Used to distinguish planned versus unplanned downtime for maintenance strategy analysis.',
    `primary_delay_category` STRING COMMENT 'The dominant category of delay or downtime that most impacted utilisation during the period (e.g., blast exclusion, fuelling, shift change, mechanical breakdown, weather, traffic). [ENUM-REF-CANDIDATE: blast_exclusion|fuelling|shift_change|mechanical_breakdown|weather|traffic|operator_fatigue|waiting_for_instructions|road_conditions|other — promote to reference product]',
    `reconciliation_variance_hours` DECIMAL(18,2) COMMENT 'Difference in total hours between the MineStar FMS automated record and the manually submitted shift report. Non-zero values trigger investigation. Supports data quality management and audit compliance.',
    `record_date` DATE COMMENT 'Calendar date for which this utilisation record applies. Used for daily aggregation, trend analysis, and LOM (Life of Mine) planning.',
    `record_status` STRING COMMENT 'Workflow status of the utilisation record indicating its data quality and approval state. Records progress from draft through reconciliation against shift reports to approved status.. Valid values are `draft|submitted|reconciled|approved|rejected`',
    `record_type` STRING COMMENT 'Granularity of the utilisation record indicating whether it represents a single shift, a daily roll-up, or a weekly summary. Determines the time horizon of the hours captured.. Valid values are `shift|daily|weekly`',
    `scheduled_hours` DECIMAL(18,2) COMMENT 'Total hours the asset was scheduled to be available for production during the shift or day, as defined in the mine production schedule. Denominator for physical availability calculations.',
    `shift_type` STRING COMMENT 'Classification of the shift during which utilisation was recorded (e.g., day, night, afternoon, rotating). Supports shift-pattern analysis and crew productivity benchmarking.. Valid values are `day|night|afternoon|rotating`',
    `standby_hours` DECIMAL(18,2) COMMENT 'Hours the asset was available and ready for deployment but not assigned to a task (e.g., awaiting operator, weather hold, blast exclusion zone). Distinguishes planned non-productive time from idle time.',
    `unplanned_maintenance_hours` DECIMAL(18,2) COMMENT 'Hours the asset was unavailable due to unexpected breakdowns or corrective maintenance. Subset of downtime_hours. High values indicate reliability issues and drive MTBF and MTTR analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this utilisation record was last modified, including reconciliation adjustments or corrections. Supports change tracking and silver layer incremental processing.',
    `use_of_availability_pct` DECIMAL(18,2) COMMENT 'Ratio of operating hours to available hours (scheduled minus downtime), expressed as a percentage. Measures how effectively the operations team uses the mechanically available asset. Complements physical availability to form the OEE framework.',
    `utilisation_pct` DECIMAL(18,2) COMMENT 'Ratio of operating hours to scheduled hours expressed as a percentage. Primary KPI for fleet productivity and LOM (Life of Mine) planning. Calculated as (operating_hours / scheduled_hours) * 100.',
    CONSTRAINT pk_utilisation_record PRIMARY KEY(`utilisation_record_id`)
) COMMENT 'Shift-level or daily utilisation records per asset capturing scheduled hours, operating hours, idle hours, standby hours, and utilisation percentage. Distinguishes physical availability from utilisation to support fleet sizing decisions and LOM planning. Sourced from MineStar FMS and reconciled against shift reports.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`payload_cycle` (
    `payload_cycle_id` BIGINT COMMENT 'Unique system-generated identifier for each individual truck payload cycle record (load-haul-dump event) as captured by Caterpillar MineStar Payload Management.',
    `commodity_order_id` BIGINT COMMENT 'Foreign key linking to sales.commodity_order. Business justification: Production-to-sales reconciliation: mining operations reconcile actual payload cycles (tonnes moved) against commodity orders to verify delivery commitments are met. Mine controllers and sales teams u',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Haulage cycles generate costs allocated to cost centres based on material type (ore, waste) and destination for mining cost accounting and cost per tonne reporting.',
    `fleet_assignment_id` BIGINT COMMENT 'Foreign key linking to equipment.fleet_assignment. Business justification: Each payload cycle (individual load-haul-dump cycle for a haul truck) occurs within the context of a specific fleet assignment. Fleet assignments define the operational context — which asset is assign',
    `grade_control_sample_id` BIGINT COMMENT 'Foreign key linking to geology.grade_control_sample. Business justification: Each truck payload cycle is directed to crusher, stockpile, or waste dump based on grade control sample results. Ore reconciliation and grade control reporting require linking payload cycles to the gr',
    `haulage_cycle_id` BIGINT COMMENT 'Foreign key linking to mine.haulage_cycle. Business justification: Payload cycles (FMS/dispatch system) and haulage cycles (mine production system) represent the same physical truck cycle from two system perspectives. Production reconciliation requires matching these',
    `asset_id` BIGINT COMMENT 'Reference to the haul truck or loader asset that performed this payload cycle, linking to the equipment master register in the equipment domain.',
    `functional_location_id` BIGINT COMMENT 'Reference to the destination location where the truck dumped its load during this cycle (e.g., ROM pad, crusher, waste dump, stockpile). Links to the mine operations location master.',
    `saleable_product_id` BIGINT COMMENT 'Foreign key linking to product.saleable_product. Business justification: Each haul cycle transports a specific saleable product. Production reconciliation, grade control, and stockpile accounting require product-level cycle tracking. Material_type and commodity are denorma',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Payload cycles are the source data for royalty calculation — royalty_payment.production_tonnage is derived from payload cycles per tenement. Royalty obligations are tenement-specific; mine accountants',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Payload cycles delivering construction material for TSF raises must reference the destination TSF for raise progress tracking, cost allocation, and volume reconciliation against tsf_raise records. dum',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this payload cycle record was first created in the data platform, used for audit trail and data lineage tracking.',
    `cycle_end_timestamp` TIMESTAMP COMMENT 'The date and time (ISO 8601 with timezone offset) when the payload cycle was completed, typically recorded as the moment the truck completed the dump and cleared the dump point in MineStar.',
    `cycle_reference` STRING COMMENT 'Externally-known alphanumeric reference number assigned by MineStar Payload Management to uniquely identify this load-haul-dump cycle for cross-system reconciliation and reporting.',
    `cycle_start_timestamp` TIMESTAMP COMMENT 'The date and time (ISO 8601 with timezone offset) when the payload cycle commenced, typically recorded as the moment the truck arrived at the load point or the loading sequence began in MineStar.',
    `cycle_status` STRING COMMENT 'Current lifecycle status of the payload cycle record. Completed indicates a full load-haul-dump sequence was executed. Partial indicates the cycle was interrupted. Aborted indicates the cycle was terminated before dump. Cancelled indicates the cycle was voided.. Valid values are `completed|partial|aborted|cancelled|in_progress`',
    `cycle_time_minutes` DECIMAL(18,2) COMMENT 'Total elapsed time for the complete load-haul-dump cycle in minutes, from arrival at the load point to completion of the dump. Sourced from MineStar cycle time tracking. Key input for haulage productivity analysis and OEE (Overall Equipment Effectiveness) calculation.',
    `data_quality_flag` STRING COMMENT 'Indicates the data quality status of this payload cycle record as assessed during ingestion into the Silver layer. Valid indicates the record passed all quality checks. Suspect indicates anomalies detected (e.g., payload outside expected range). Invalid indicates the record failed quality checks. Corrected indicates the record was manually reviewed and adjusted.. Valid values are `valid|suspect|invalid|corrected`',
    `dump_time_minutes` DECIMAL(18,2) COMMENT 'Time in minutes taken to complete the dump operation at the dump point during this cycle, from arrival at the dump to departure. Used to identify dump point congestion and assess dump efficiency.',
    `fuel_consumed_litres` DECIMAL(18,2) COMMENT 'Volume of diesel fuel consumed in litres during this payload cycle as recorded by the trucks on-board fuel monitoring system integrated with MineStar. Used for fuel cost allocation, OPEX tracking, and carbon emissions reporting.',
    `haul_distance_empty_m` DECIMAL(18,2) COMMENT 'Distance in metres travelled by the truck empty from the dump point back to the load point during this cycle, as recorded by MineStar GPS/telematics. Used for total cycle distance calculation and fuel consumption analysis.',
    `haul_distance_loaded_m` DECIMAL(18,2) COMMENT 'Distance in metres travelled by the truck from the load point to the dump point while carrying a full load during this cycle, as recorded by MineStar GPS/telematics. Used for haulage cost modelling and route optimisation.',
    `haul_time_loaded_minutes` DECIMAL(18,2) COMMENT 'Time in minutes the truck spent travelling from the load point to the dump point while carrying a full load during this cycle. Used for haulage route analysis and cycle time optimisation.',
    `load_time_minutes` DECIMAL(18,2) COMMENT 'Time in minutes taken to load the truck at the dig face or load point during this cycle, from first bucket to last bucket. Used to assess loader productivity and number of passes per load.',
    `minestar_cycle_code` STRING COMMENT 'The native cycle identifier assigned by Caterpillar MineStar Payload Management system at the source. Retained for traceability and reconciliation back to the operational system of record.',
    `number_of_passes` STRING COMMENT 'The number of bucket or dipper passes (swings) made by the loading unit to fill the truck to the target payload during this cycle. Used to assess loader efficiency and optimise pass-matching strategy.',
    `operator_name` STRING COMMENT 'Full name of the equipment operator who performed this payload cycle as recorded in MineStar at the time of the cycle. Retained for operational reporting and shift reconciliation where the operator ID may not be immediately resolvable.',
    `overload_flag` BOOLEAN COMMENT 'Indicates whether the truck was loaded beyond its rated payload capacity (overloaded) during this cycle as determined by MineStar payload monitoring. True indicates an overload event. Used for truck health monitoring, tyre management, and compliance with OEM load limits.',
    `payload_measurement_method` STRING COMMENT 'The method used to measure the payload weight for this cycle. Onboard scale uses the trucks integrated weighing system. Strut pressure uses suspension strut pressure sensors. Load cell uses a fixed weighbridge. Estimated indicates a calculated value. Manual indicates a manually entered value. Affects data quality confidence for ROM reconciliation.. Valid values are `onboard_scale|strut_pressure|load_cell|estimated|manual`',
    `payload_variance_tonnes` DECIMAL(18,2) COMMENT 'The difference between the actual payload weight and the target payload weight in metric tonnes (actual minus target). Positive values indicate overloading; negative values indicate underloading. Used for truck health monitoring and haulage efficiency analysis. Note: this is a raw recorded field from MineStar, not a derived KPI.',
    `payload_weight_tonnes` DECIMAL(18,2) COMMENT 'The measured weight of material loaded onto the truck during this cycle, expressed in metric tonnes as recorded by the on-board payload measurement system (OBMS) in MineStar. This is the principal quantitative fact for the cycle and the primary input to ROM tonnage reconciliation.',
    `production_date` DATE COMMENT 'The calendar date on which this payload cycle was executed, used for daily production reporting, ROM tonnage reconciliation against the Life of Mine (LOM) plan, and shift-based aggregation.',
    `queue_time_minutes` DECIMAL(18,2) COMMENT 'Time in minutes the truck spent waiting in queue at the load point before loading commenced during this cycle. Used to identify loader bottlenecks, optimise truck-shovel matching, and reduce non-productive time.',
    `return_time_minutes` DECIMAL(18,2) COMMENT 'Time in minutes the truck spent travelling empty from the dump point back to the load point during this cycle. Used for haulage route analysis and cycle time component breakdown.',
    `shift_type` STRING COMMENT 'Classification of the production shift during which this cycle occurred (day, night, or afternoon). Used for shift-comparative productivity analysis and fatigue risk management.. Valid values are `day|night|afternoon`',
    `target_payload_tonnes` DECIMAL(18,2) COMMENT 'The planned or nominal target payload weight in metric tonnes for this truck model and material type as configured in MineStar. Used to calculate payload variance and assess overloading or underloading against truck rated capacity.',
    `truck_fleet_number` STRING COMMENT 'Human-readable fleet identification number assigned to the haul truck or loader (e.g., HT-042, LD-017) as registered in the Fleet Management System (FMS). Used for operational reporting and shift reconciliation.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this payload cycle record was last modified in the data platform, used for change tracking and incremental data processing.',
    CONSTRAINT pk_payload_cycle PRIMARY KEY(`payload_cycle_id`)
) COMMENT 'Individual truck payload cycle records capturing each load-haul-dump cycle for haul trucks and loaders. Includes load location, dump location, payload weight (tonnes), cycle time, queue time, travel time, and operator. Sourced from MineStar Payload Management. Used for haulage productivity analysis and ROM tonnage reconciliation.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`inspection` (
    `inspection_id` BIGINT COMMENT 'Unique surrogate identifier for each equipment inspection record in the silver layer lakehouse. Primary key for this data product. Entity role: TRANSACTION_HEADER — a discrete, lifecycle-managed business event (pre-start or periodic inspection) with regulatory standing.',
    `asset_id` BIGINT COMMENT 'Reference to the equipment asset (haul truck, drill, shovel, conveyor, processing plant unit, etc.) that was inspected. Links to the equipment master register sourced from Infor EAM and Caterpillar MineStar. Satisfies TRANSACTION_HEADER PARTY_REFERENCE / MASTER_RESOURCE category.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to hse.audit. Business justification: Equipment inspections are frequently scheduled as part of formal HSE audits (ISO 45001, regulatory compliance audits). Linking inspections to the parent audit enables audit finding aggregation, correc',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Inspection costs (labor, materials) are allocated to cost centres for maintenance budget tracking and compliance cost reporting in mining operations.',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Statutory and regulatory inspections in mining are tied to functional locations for compliance reporting (e.g., inspect crusher FL-PROC-001). inspection.location_description is a denormalized text fie',
    `hazard_id` BIGINT COMMENT 'Foreign key linking to hse.hazard. Business justification: Pre-start and statutory equipment inspections in mining identify specific hazards from the hazard register. Linking inspection findings directly to hazard records enables hazard trend analysis, bow-ti',
    `incident_id` BIGINT COMMENT 'Reference to an associated HSE incident record in IsoMetrix if this inspection was triggered by or linked to a safety incident (e.g., post-incident inspection). Null for routine pre-start and periodic inspections.',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site or operational location where the inspection was conducted. Supports site-level compliance reporting and regulatory submissions per jurisdiction.',
    `pm_schedule_id` BIGINT COMMENT 'Foreign key linking to maintenance.pm_schedule. Business justification: Inspections are generated from PM schedules in mining EAM systems. PM compliance reporting requires tracing each inspection back to the originating PM schedule without traversing work_order. Regulator',
    `previous_inspection_id` BIGINT COMMENT 'Self-referencing FK on inspection (previous_inspection_id)',
    `regulatory_condition_id` BIGINT COMMENT 'Foreign key linking to tenement.regulatory_condition. Business justification: Equipment inspections are frequently mandated by specific tenement regulatory conditions (regulatory_condition.inspection_required_flag). Compliance teams must demonstrate that each inspection satisfi',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Equipment inspections identify hazards (worn components, safety system failures, structural defects) that feed into risk assessments. Inspection findings directly inform residual risk ratings and cont',
    `standard_job_id` BIGINT COMMENT 'Foreign key linking to maintenance.standard_job. Business justification: Inspection checklists in mining EAM are defined as standard job plans. Linking inspection to standard_job enables checklist compliance tracking, revision control (knowing which job plan version was us',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Equipment inspections mandated by tenement regulatory conditions must be traceable to the tenement licence area. Regulatory compliance audits cross-reference inspection records against tenement licenc',
    `tsf_id` BIGINT COMMENT 'Foreign key linking to tailings.tsf. Business justification: Equipment inspections performed at a TSF (decant infrastructure, pumps, instrumentation) must reference the specific TSF for regulatory dam safety audit trails and facility-level compliance reporting.',
    `work_order_id` BIGINT COMMENT 'Reference to the corrective maintenance work order generated in Infor EAM as a result of defect findings identified during this inspection. Null if no corrective action was required or work order has not yet been raised.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the supervising officer approved the inspection record. Null if not yet approved or approval not required. Supports regulatory audit trails for statutory inspections.',
    `checklist_items_completed` STRING COMMENT 'Number of checklist items that were assessed and recorded during this inspection. A value less than checklist_items_total may indicate an incomplete inspection, which is a compliance risk for pre-start and statutory inspections.',
    `checklist_items_total` STRING COMMENT 'Total number of checklist items included in the inspection for this equipment class and inspection type. Used to calculate completion rate and to validate that all mandatory items were assessed.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether one or more defect findings from this inspection require a corrective action to be raised. True triggers work order generation in Infor EAM and/or a corrective action task in IsoMetrix. Critical for HSE compliance workflow integration.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inspection record was first created in the source system. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category. Used for data lineage and audit trail purposes.',
    `defect_count_critical` STRING COMMENT 'Number of checklist items rated as critical severity during this inspection. Critical defects require immediate equipment shutdown and corrective action before operation can resume. A value greater than zero should result in a fail overall result.',
    `defect_count_major` STRING COMMENT 'Number of checklist items rated as major severity during this inspection. Major defects require corrective action within a defined timeframe but may allow conditional operation under specified controls.',
    `defect_count_minor` STRING COMMENT 'Number of checklist items rated as minor severity during this inspection. Minor defects are recorded for monitoring and scheduled maintenance but do not prevent equipment operation.',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the inspector completed and submitted the inspection. Used to calculate inspection duration and to confirm the inspection was completed before equipment operation commenced (pre-start compliance).',
    `equipment_class` STRING COMMENT 'Classification of the equipment type being inspected. Determines which checklist template applies and which regulatory requirements govern the inspection. Sourced from the equipment master register in Infor EAM and Caterpillar MineStar. [ENUM-REF-CANDIDATE: haul_truck|drill|shovel|excavator|dozer|grader|conveyor|crusher|processing_plant|light_vehicle — promote to reference product]',
    `equipment_grounded` BOOLEAN COMMENT 'Indicates whether the equipment was taken out of service (grounded) as a result of this inspection. True means the equipment must not be operated until corrective action is completed and a return-to-service inspection is passed. Directly impacts fleet availability and OEE calculations.',
    `equipment_hours_at_inspection` DECIMAL(18,2) COMMENT 'Engine or operating hours recorded on the equipment at the time of inspection. Used to determine whether periodic maintenance-based inspections are due and to track equipment utilisation context at the time of the inspection. Sourced from Caterpillar MineStar telematics.',
    `equipment_tag` STRING COMMENT 'Human-readable fleet number or asset tag of the equipment being inspected (e.g., HT-042, DR-007). Denormalized from the equipment master for operational convenience and to support inspection records even when the equipment master FK is temporarily unavailable.',
    `inspection_method` STRING COMMENT 'Method by which the inspection was captured and submitted. Mobile app refers to field-based digital capture. Paper form indicates a manual record subsequently digitised. Desktop portal is a web-based entry. Integrated OBC (on-board computer) refers to direct capture from Caterpillar MineStar on-board systems.. Valid values are `mobile_app|paper_form|desktop_portal|integrated_obc`',
    `inspection_number` STRING COMMENT 'Externally-known, human-readable business identifier for the inspection record as assigned by the source system (IsoMetrix or Infor EAM). Used for cross-system reference, regulatory submissions, and audit trails. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^INSP-[0-9]{4}-[0-9]{6}$`',
    `inspection_status` STRING COMMENT 'Current workflow state of the inspection record. Draft indicates the inspection is in progress or not yet submitted. Submitted means the inspector has completed and lodged the record. Approved indicates supervisor sign-off. Rejected means the record was returned for correction. Cancelled applies to inspections that were voided. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category.. Valid values are `draft|submitted|approved|rejected|cancelled`',
    `inspection_type` STRING COMMENT 'Classification of the inspection by its regulatory or operational trigger. Pre-start inspections are legally mandated before equipment operation in most mining jurisdictions. Periodic inspections occur at scheduled intervals. Post-incident inspections follow a safety event. Statutory inspections are required by specific mining regulations. Return-to-service inspections occur after maintenance or repair.. Valid values are `pre_start|periodic|post_incident|statutory|return_to_service`',
    `inspector_comments` STRING COMMENT 'Free-text narrative comments provided by the inspector to describe defect findings, operational context, or observations not captured by the structured checklist items. Supports incident investigation and root cause analysis.',
    `inspector_competency_code` STRING COMMENT 'Competency or certification code held by the inspector that authorises them to conduct this class of inspection (e.g., operator licence number, statutory inspector certificate). Required for regulatory compliance verification. Sourced from SAP HR competency records.',
    `inspector_role` STRING COMMENT 'Role of the person conducting the inspection. Operators conduct pre-start checks. Maintainers conduct post-maintenance checks. Supervisors conduct periodic and statutory inspections. Statutory inspectors are government-appointed or certified inspectors. Third-party inspectors are external contractors.. Valid values are `operator|maintainer|supervisor|statutory_inspector|third_party`',
    `odometer_km` DECIMAL(18,2) COMMENT 'Odometer reading in kilometres recorded at the time of inspection, applicable to mobile equipment such as haul trucks and light vehicles. Null for fixed plant and equipment without odometers. Supports distance-based maintenance scheduling.',
    `overall_result` STRING COMMENT 'Aggregate pass/fail outcome of the inspection. Pass indicates all checklist items met the required standard. Fail indicates one or more critical or major defects were found that prevent safe operation. Conditional pass indicates minor defects noted but equipment may operate under specified conditions pending corrective action.. Valid values are `pass|fail|conditional_pass`',
    `photo_evidence_count` STRING COMMENT 'Number of photographic evidence items attached to this inspection record to document defect findings. Supports regulatory audit requirements and insurance claims. Photos are stored in the document management system with references captured at the checklist item level.',
    `regulatory_standard` STRING COMMENT 'The specific mining safety regulation or standard under which this inspection is mandated or conducted. Enables jurisdiction-specific compliance reporting and regulatory submissions. [ENUM-REF-CANDIDATE: MSHA_30CFR56|MSHA_30CFR57|WHS_ACT|DMIRS_WA|MINES_ACT_QLD|ISO_45001 — promote to reference product]. Valid values are `MSHA_30CFR56|MSHA_30CFR57|WHS_ACT|DMIRS_WA|MINES_ACT_QLD|ISO_45001`',
    `shift_type` STRING COMMENT 'The shift during which the inspection was conducted. Pre-start inspections are typically conducted at the commencement of each shift. Used for shift-level compliance reporting and to correlate inspection outcomes with shift patterns.. Valid values are `day|night|afternoon`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this inspection record was ingested into the lakehouse silver layer. Supports data lineage, reconciliation, and troubleshooting of ETL pipelines.. Valid values are `IsoMetrix|InforEAM|MobileApp|MineStar`',
    `source_system_record_code` STRING COMMENT 'The native primary key or record identifier of this inspection in the originating source system (IsoMetrix, Infor EAM, or mobile app). Enables back-referencing to the source system for reconciliation and audit purposes.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the inspector commenced the inspection. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category. Critical for regulatory compliance — pre-start inspections must be completed before equipment operation commences.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this inspection record was last modified in the source system. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category. Tracks amendments, supervisor approvals, and corrective action updates.',
    CONSTRAINT pk_inspection PRIMARY KEY(`inspection_id`)
) COMMENT 'Pre-start and periodic equipment inspection records completed by operators, maintainers, and supervisors as required by mining safety regulations (e.g., WHS Act, MSHA 30 CFR Part 56/57). Captures inspection type (pre-start, periodic, post-incident, statutory), checklist items per equipment class, defect findings with photo evidence references, severity rating (critical/major/minor), pass/fail status, corrective action required flag, and inspector identity with competency verification. Critical for regulatory compliance — pre-start inspections are legally mandated before equipment operation in most mining jurisdictions. Linked to HSE incident workflows and maintenance work order generation. Sourced from IsoMetrix, Infor EAM, and mobile inspection apps.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`asset_lifecycle_event` (
    `asset_lifecycle_event_id` BIGINT COMMENT 'Unique surrogate identifier for each asset lifecycle event record in the silver layer. Primary key for the asset_lifecycle_event data product.',
    `asset_id` BIGINT COMMENT 'Reference to the mining fleet or fixed plant asset (e.g., haul truck, drill, shovel, conveyor, processing equipment) that this lifecycle event applies to. Links to the equipment master register.',
    `component_register_id` BIGINT COMMENT 'Foreign key linking to equipment.component_register. Business justification: Asset lifecycle events such as major rebuilds, engine replacements, and component overhauls directly reference specific components tracked in the component_register. The asset_lifecycle_event table cu',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to hse.corrective_action. Business justification: Corrective actions from HSE incidents or audits can mandate asset lifecycle changes (decommission, modification, relocation). Mining MoC and corrective action closure processes require tracing which c',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Asset lifecycle events (transfers, disposals, overhauls) are charged to a cost centre for financial reporting and AISC cost allocation. The event table carries a denormalized cost_centre_code; a prope',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Asset lifecycle events (disposal, revaluation, impairment, transfer) directly trigger fixed asset accounting entries under IFRS/AASB116. The lifecycle event must reference the fixed asset record to dr',
    `functional_location_id` BIGINT COMMENT 'Foreign key linking to maintenance.functional_location. Business justification: Asset lifecycle events (installation, transfer, decommission) occur at specific functional locations. Mining EAM systems track asset-to-FL history for maintenance history continuity, insurance valuati',
    `heritage_clearance_id` BIGINT COMMENT 'Foreign key linking to tenement.heritage_clearance. Business justification: Ground-disturbing asset lifecycle events (commissioning new infrastructure, earthworks) require heritage clearance before proceeding. Mine planning and tenement teams must confirm a valid heritage cle',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Major lifecycle events (commissioning, decommissioning, major overhauls) can trigger incidents (commissioning accidents, decommissioning spills) or be incident outcomes (asset written off after major ',
    `mine_site_id` BIGINT COMMENT 'Reference to the mine site from which the asset was relocated, applicable when event_type is relocation. Enables tracking of inter-site asset movements for fleet optimisation and fixed asset register updates.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_purchase_order. Business justification: Capital expenditure tracking: major asset lifecycle events (acquisition, major overhaul, disposal) are funded by specific purchase orders. Mining capital project reporting requires linking lifecycle e',
    `risk_assessment_id` BIGINT COMMENT 'Foreign key linking to hse.risk_assessment. Business justification: Mining Management of Change (MoC) process mandates a risk assessment before commissioning, decommissioning, or major overhaul of equipment. Links lifecycle events to the governing risk assessment for ',
    `shutdown_plan_id` BIGINT COMMENT 'Foreign key linking to maintenance.shutdown_plan. Business justification: Major asset lifecycle events (capital rebuilds, major overhauls, decommissions) are executed within planned shutdowns. Linking asset_lifecycle_event to shutdown_plan enables capital expenditure tracki',
    `tenement_id` BIGINT COMMENT 'Foreign key linking to tenement.tenement. Business justification: Asset commissioning, decommissioning, and transfer events on a tenement must be reported to regulatory authorities as part of tenement compliance and mine closure planning. Tenement managers track whi',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Major lifecycle events (commissioning, major overhauls, decommissioning) may be capitalized and tracked against WBS elements for capital project accounting and asset valuation.',
    `work_order_id` BIGINT COMMENT 'SAP Plant Maintenance or Infor EAM work order number associated with this lifecycle event. Provides traceability to the originating maintenance work order for audit and cost reconciliation purposes.',
    `asset_condition_rating` STRING COMMENT 'Assessed physical condition of the asset immediately following the lifecycle event, as determined by the maintenance engineer or inspector. Used for insurance valuation, capital planning, and remaining useful life estimation. Ratings: excellent = like-new post-rebuild; good = minor wear; fair = moderate wear requiring monitoring; poor = significant degradation; critical = imminent failure risk.. Valid values are `excellent|good|fair|poor|critical`',
    `asset_hours_at_event` DECIMAL(18,2) COMMENT 'Total cumulative operating hours recorded on the asset at the time of the lifecycle event (e.g., engine hours at rebuild). Used to calculate Mean Time Between Failures (MTBF), validate rebuild intervals, and benchmark against OEM recommended service intervals.',
    `book_value_at_event` DECIMAL(18,2) COMMENT 'Net book value of the asset on the fixed asset register at the time of the lifecycle event, in the reporting currency. Used for CAPEX capitalisation decisions, impairment testing, and disposal gain/loss calculations.',
    `cost_classification` STRING COMMENT 'Financial classification of the cost incurred for this lifecycle event. CAPEX (Capital Expenditure) = costs that extend asset life or add capability, capitalised to the fixed asset register; OPEX (Operating Expenditure) = costs expensed in the period. Critical for fixed asset register reconciliation, tax treatment, and financial reporting under IFRS.. Valid values are `capex|opex`',
    `cost_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the event_cost amount (e.g., AUD, USD, ZAR). Required for multi-currency operations across international mining jurisdictions.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lifecycle event record was first created in the data platform (silver layer ingestion time). Used for data lineage, audit trail, and reconciliation with source systems.',
    `depreciation_method` STRING COMMENT 'Depreciation method applied to the asset following this lifecycle event. May be updated after a major rebuild or change in remaining useful life estimate. Straight_line = equal annual charge; units_of_production = charge based on actual production output; declining_balance = accelerated depreciation.. Valid values are `straight_line|units_of_production|declining_balance`',
    `eam_event_number` STRING COMMENT 'Externally-known business identifier for the lifecycle event as recorded in Infor EAM (e.g., work order number, event reference number). Used for cross-system reconciliation with SAP Fixed Asset Register and insurance systems.',
    `event_cost` DECIMAL(18,2) COMMENT 'Total cost incurred for this lifecycle event in the reporting currency. Includes labour, materials, contractor fees, and overheads. Used for CAPEX/OPEX tracking, insurance valuation, and All-In Sustaining Cost (AISC) calculations.',
    `event_date` DATE COMMENT 'The actual calendar date on which the lifecycle event occurred or was formally executed (e.g., commissioning date, rebuild completion date, decommissioning date). This is the principal real-world business event date used for fixed asset register updates and insurance valuation.',
    `event_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the lifecycle event work was completed and the asset was returned to service or formally closed. Used to calculate event duration and Mean Time To Repair (MTTR) impact.',
    `event_notes` STRING COMMENT 'Free-text field for additional technical or operational notes recorded by the maintenance engineer or planner regarding this lifecycle event (e.g., observed failure mode, special conditions, deviations from standard procedure, OEM recommendations).',
    `event_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the lifecycle event work commenced (e.g., when the rebuild began, when the asset was powered down for decommissioning). Used for duration calculation and OEE impact analysis.',
    `event_status` STRING COMMENT 'Current workflow status of the lifecycle event. Planned = scheduled but not yet started; in_progress = work underway; completed = event fully executed and closed; cancelled = event voided before execution; on_hold = temporarily suspended pending approval or parts.. Valid values are `planned|in_progress|completed|cancelled|on_hold`',
    `event_type` STRING COMMENT 'Classification of the significant lifecycle milestone for the asset. Commissioning = first entry into service; major_rebuild = engine, transmission, or hydraulic system overhaul; component_replacement = scheduled or unscheduled part swap; mid_life_refurbishment = comprehensive mid-cycle restoration; relocation = transfer between mine sites or operational areas; standby_mothballing = temporary suspension of operations; ownership_change = lease return or sale; decommissioning_disposal = permanent retirement and disposal. [ENUM-REF-CANDIDATE: commissioning|major_rebuild|component_replacement|mid_life_refurbishment|relocation|standby_mothballing|ownership_change|decommissioning_disposal — 8 candidates stripped; promote to reference product]',
    `hse_clearance_required` BOOLEAN COMMENT 'Indicates whether a formal Health, Safety and Environment (HSE) clearance or permit was required to execute this lifecycle event (e.g., confined space entry permit for major rebuild, environmental permit for decommissioning). Supports ISO 45001 and ISO 14001 compliance tracking.',
    `hse_permit_number` STRING COMMENT 'Reference number of the HSE permit or work clearance certificate issued for this lifecycle event (e.g., Permit to Work number, Isolation Certificate number). Populated when hse_clearance_required is true. Traceable to IsoMetrix HSE system.',
    `insurance_valuation` DECIMAL(18,2) COMMENT 'Updated insurance replacement value of the asset following this lifecycle event, in the reporting currency. Revised after major rebuilds, refurbishments, or condition assessments. Used for insurance policy management and asset register reconciliation.',
    `odometer_km_at_event` DECIMAL(18,2) COMMENT 'Total cumulative distance in kilometres recorded on the asset at the time of the lifecycle event. Applicable for mobile mining equipment (haul trucks, light vehicles). Complements operating hours for maintenance interval tracking.',
    `ownership_transfer_type` STRING COMMENT 'Specifies the nature of the ownership change when event_type is ownership_change. Lease_return = asset returned to lessor at end of lease term; sale = asset sold to third party; purchase = asset acquired; internal_transfer = transfer between legal entities within the mining group.. Valid values are `lease_return|sale|purchase|internal_transfer`',
    `planned_event_date` DATE COMMENT 'The originally scheduled date for the lifecycle event as per the maintenance or capital plan. Compared against event_date to measure schedule adherence and support Life of Mine (LOM) capital planning.',
    `remaining_useful_life_months` STRING COMMENT 'Updated estimate of the assets remaining useful life in months following this lifecycle event, as assessed by the maintenance engineer. Revised after major rebuilds, refurbishments, or condition assessments. Critical for capital planning, depreciation schedules, and Life of Mine (LOM) fleet replacement planning.',
    `responsible_party_name` STRING COMMENT 'Name of the internal team, maintenance crew, or external contractor responsible for executing the lifecycle event (e.g., OEM Rebuild Team - Caterpillar, Site Maintenance Crew A). Retained for reporting without requiring a join.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this lifecycle event record was sourced. Infor_eam = Infor Enterprise Asset Management; sap_pm = SAP S/4HANA Plant Maintenance; minestar = Caterpillar MineStar Equipment Health; manual = manually entered record.. Valid values are `infor_eam|sap_pm|minestar|manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this lifecycle event record was last modified in the data platform. Used for incremental load detection, change data capture, and audit trail management.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the OEM or contractor warranty for the rebuilt or replaced component expires following this lifecycle event. Used to manage warranty claims and schedule post-warranty maintenance.',
    CONSTRAINT pk_asset_lifecycle_event PRIMARY KEY(`asset_lifecycle_event_id`)
) COMMENT 'Tracks significant lifecycle milestones for each asset including commissioning, major rebuild (engine, transmission, hydraulic system), component replacement, mid-life refurbishment, relocation between sites, temporary standby/mothballing, change of ownership (lease return, sale), and final decommissioning/disposal. Captures event type, event date, responsible party, cost incurred (CAPEX vs OPEX classification), resulting asset condition rating, and updated remaining useful life estimate. Critical for fixed asset register reconciliation, insurance valuation, and capital planning. Sourced from Infor EAM and finance system (SAP/Oracle).';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`component_register` (
    `component_register_id` BIGINT COMMENT 'Unique surrogate identifier for each serialised component record in the master register. Primary key for the component_register data product.',
    `asset_id` BIGINT COMMENT 'Reference to the parent mining asset (haul truck, drill, shovel, conveyor, mill, etc.) on which this component is currently installed. Sourced from Infor EAM equipment master.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Component rebuild and replacement costs are allocated to cost centres for maintenance cost tracking, AISC calculation, and cost per operating hour analysis. Reusing existing cost_centre_code.',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Under IAS 16 component accounting, major components (engines, transmissions, ground engaging tools) above capitalisation threshold are separately recognised as fixed assets with individual depreciatio',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Serialised component traceability: critical mining components (engines, gearboxes, hydraulic pumps) are tracked by serial number from goods receipt through installation and rebuild cycles. This link s',
    `hazard_id` BIGINT COMMENT 'Foreign key linking to hse.hazard. Business justification: Critical components (hydraulic accumulators, asbestos gaskets, pressurised vessels) carry inherent hazards requiring registration in the hazard register. Mining asset management and HSE require linkin',
    `parent_component_register_id` BIGINT COMMENT 'Self-referencing FK on component_register (parent_component_register_id)',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to procurement.material_master. Business justification: Spare parts and component procurement: every tracked component (engine, pump, gearbox) maps to a material master for stock management, reorder, and cost valuation. Mining EAM/SAP integration requires ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Components (engines, transmissions, hydraulics) have OEM suppliers; tracking vendor per component enables targeted parts sourcing, supplier performance analysis, and warranty claims. Real business pro',
    `wbs_element_id` BIGINT COMMENT 'Foreign key linking to finance.wbs_element. Business justification: Component replacements above capitalisation threshold (engine rebuilds, major structural repairs) are charged to WBS elements as CAPEX projects. Linking component_register to wbs_element enables CAPEX',
    `component_class` STRING COMMENT 'High-level engineering classification grouping components by their functional and failure mode characteristics. Used to apply appropriate condition monitoring strategies and maintenance standards.. Valid values are `rotating|structural|hydraulic|electrical|ground_engaging|wear`',
    `component_name` STRING COMMENT 'Descriptive name of the component (e.g., Engine Assembly, Final Drive LH, SAG Mill Liner Set, Hydraulic Pump Main). Human-readable label used in maintenance planning and reporting.',
    `component_number` STRING COMMENT 'Unique business-facing identifier for the component record within the Infor EAM system. Used for cross-referencing with maintenance work orders and procurement records.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `component_status` STRING COMMENT 'Current lifecycle status of the component. Drives inventory availability, maintenance scheduling, and rebuild/replace decision workflows within Infor EAM.. Valid values are `installed|in_store|in_rebuild|condemned|scrapped|on_order`',
    `component_type` STRING COMMENT 'Classification of the major replaceable component category. Drives applicable life limits, rebuild standards, and condition monitoring protocols. [ENUM-REF-CANDIDATE: engine|transmission|final_drive|hydraulic_pump|get|mill_liner|conveyor_drive|differential|torque_converter|alternator|pump|motor|gearbox|brake_assembly|suspension — promote to reference product]',
    `condition_assessment_date` DATE COMMENT 'Date on which the most recent condition assessment was performed for this component. Used to determine assessment currency and trigger re-inspection schedules.',
    `condition_assessment_method` STRING COMMENT 'Technique used to determine the current condition rating of the component. Supports traceability of condition data and selection of appropriate monitoring strategies.. Valid values are `oil_analysis|vibration|visual|thermography|ultrasonic|borescope`',
    `condition_rating` STRING COMMENT 'Current assessed condition rating of the component based on inspection, oil analysis, vibration monitoring, or visual assessment. Drives condition-based maintenance (CBM) decisions and rebuild/replace recommendations.. Valid values are `excellent|good|fair|poor|critical`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to rebuild_cost and replacement_cost fields (e.g., AUD, USD, ZAR). Supports multi-currency operations across international mining sites.. Valid values are `^[A-Z]{3}$`',
    `eam_component_code` STRING COMMENT 'Source system identifier for this component record within Infor EAM. Enables data lineage traceability and reconciliation between the Silver layer data product and the operational system of record.',
    `hours_at_installation` DECIMAL(18,2) COMMENT 'Accumulated hours recorded on this component at the time of its most recent installation onto the parent asset. Used to calculate hours accrued during the current installation period.',
    `hours_since_new` DECIMAL(18,2) COMMENT 'Accumulated operating hours on this component since it was manufactured new. Includes all installation periods across its full lifecycle. Key metric for life-to-date tracking and OEM warranty assessment.',
    `hours_since_rebuild` DECIMAL(18,2) COMMENT 'Accumulated operating hours on this component since its most recent rebuild or remanufacture. Primary metric for condition-based maintenance triggers and rebuild interval management.',
    `installation_date` DATE COMMENT 'Date on which this component was most recently installed onto the parent asset. Used to calculate time-in-service and trigger scheduled replacement intervals.',
    `is_critical_component` BOOLEAN COMMENT 'Indicates whether this component is classified as safety-critical or production-critical under the sites critical equipment register. Critical components require enhanced inspection frequencies and mandatory hold points per ISO 45001.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent formal inspection or condition monitoring event performed on this component. Used to track inspection compliance and schedule next inspection.',
    `manufacture_date` DATE COMMENT 'Date on which this component was originally manufactured. Used for age-based life assessments, warranty eligibility determination, and calendar-based replacement planning.',
    `max_rebuild_limit` STRING COMMENT 'OEM or engineering-approved maximum number of rebuilds permitted for this component type before mandatory condemnation and replacement. Enforces safe life limits.',
    `model_number` STRING COMMENT 'OEM model or specification number for this component. Distinguishes variants within the same component type (e.g., different engine ratings or transmission ratios) for compatibility verification.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next mandatory inspection or condition monitoring event for this component. Drives preventive maintenance scheduling in Infor EAM and ensures compliance with site inspection regimes.',
    `oem_part_number` STRING COMMENT 'Original Equipment Manufacturer (OEM) catalogue part number for this component. Used for procurement, warranty claims, and interchangeability verification against approved parts lists.',
    `oil_sample_reference` STRING COMMENT 'Laboratory reference number for the most recent oil or fluid analysis sample taken from this component. Links to LabWare LIMS for detailed oil analysis results used in condition-based maintenance decisions.',
    `position_code` STRING COMMENT 'Standardised code identifying the specific mounting position on the parent asset where this component is installed (e.g., LH_FRONT, DRIVE_1, MILL_FEED_END). Enables position-specific wear pattern analysis.',
    `rebuild_cost` DECIMAL(18,2) COMMENT 'Actual cost incurred for the most recent rebuild of this component in the site operating currency. Used for rebuild/replace economic analysis and OPEX reporting. Sourced from SAP S/4HANA PM/CO.',
    `rebuild_count` STRING COMMENT 'Total number of times this component has been rebuilt or remanufactured over its lifetime. Used in rebuild/replace decision analysis and to assess cumulative fatigue against OEM rebuild limits.',
    `rebuild_replace_decision` STRING COMMENT 'Current engineering or maintenance decision on the disposition of this component at end of its current service life. Informs CAPEX/OPEX planning and component exchange pool management.. Valid values are `rebuild|replace|monitor|condemn|pending_assessment`',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this component register record in the Silver layer. Supports incremental data loading, audit trails, and change detection for downstream consumers.',
    `remaining_life_hours` DECIMAL(18,2) COMMENT 'Estimated remaining operating hours before this component reaches its target life limit or requires rebuild/replacement. Calculated as target_life_hours minus hours_since_rebuild. Drives proactive maintenance scheduling.',
    `removal_date` DATE COMMENT 'Date on which this component was most recently removed from the parent asset. Null if the component is currently installed. Used to calculate actual service life per installation.',
    `replacement_cost` DECIMAL(18,2) COMMENT 'Current estimated cost to replace this component with a new OEM unit. Used in rebuild/replace decision analysis and CAPEX budget planning. Sourced from Pronto Xi procurement catalogue.',
    `serial_number` STRING COMMENT 'Manufacturer-assigned serial number uniquely identifying this physical component unit. Enables full traceability across its entire lifecycle including multiple installations and rebuilds.',
    `storage_location` STRING COMMENT 'Physical warehouse bin, yard, or storage location where this component is held when not installed (e.g., WAREHOUSE-A-B12, REBUILD-SHOP-FLOOR). Sourced from Pronto Xi inventory management.',
    `target_life_hours` DECIMAL(18,2) COMMENT 'OEM or site-defined target operating hours for this component before scheduled replacement or rebuild. Basis for component life planning and budget forecasting within the Life of Mine (LOM) plan.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the OEM or remanufacturer warranty for this component expires. Ensures warranty claims are lodged within valid periods and informs make-vs-buy decisions for repairs.',
    CONSTRAINT pk_component_register PRIMARY KEY(`component_register_id`)
) COMMENT 'Master register of major replaceable components tracked at individual serial number level including engines, transmissions, final drives, hydraulic pumps, GET (ground engaging tools), mill liners, and conveyor drives. Each record represents a serialised component with OEM part number, serial number, currently installed asset, installation date, accumulated hours since last rebuild, condition rating, and rebuild history count. Supports component life tracking, condition-based maintenance triggers, and rebuild/replace decision-making. Sourced from Infor EAM.';

CREATE OR REPLACE TABLE `mining_ecm`.`equipment`.`tyre_record` (
    `tyre_record_id` BIGINT COMMENT 'Unique surrogate identifier for each tyre lifecycle record in the tyre management system. Primary key for the tyre_record data product.',
    `asset_id` BIGINT COMMENT 'Reference to the mobile equipment unit (haul truck, articulated dump truck, grader, or other mobile plant) on which this tyre is or was installed. Links to the equipment master register.',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Tyre costs are significant in mining operations and tracked by cost centre for cost per tonne analysis, AISC calculation, and maintenance budget management.',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Tyre serial number traceability: mining tyre management requires full traceability from goods receipt (vendor delivery, batch/serial number) through installation to removal. This link enables warranty',
    `incident_id` BIGINT COMMENT 'Foreign key linking to hse.incident. Business justification: Haul truck tyre blowouts are a major safety hazard in mining. When a tyre failure causes or contributes to an HSE incident, the tyre record must reference the incident for investigation, regulatory re',
    `mine_site_id` BIGINT COMMENT 'Foreign key linking to mine.mine_site. Business justification: Tyre performance (TKPH, tread wear, removal reasons) is benchmarked per mine site due to site-specific haul road conditions. Tyre cost reporting and OEM warranty claims are managed at mine site level.',
    `retreaded_from_tyre_record_id` BIGINT COMMENT 'Self-referencing FK on tyre_record (retreaded_from_tyre_record_id)',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to procurement.material_master. Business justification: Tyre procurement and inventory management: mining tyres are high-value consumables managed as material master records in SAP/EAM. This link enables reorder point monitoring, stock replenishment planni',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Tyres are high-cost consumables procured from specific vendors; linking enables vendor performance tracking (cost-per-hour by supplier), warranty claims, and procurement optimization. Real business pr',
    `work_order_id` BIGINT COMMENT 'Reference to the Infor EAM work order associated with the tyre installation or removal event, enabling traceability to the maintenance activity.',
    `accumulated_hours` DECIMAL(18,2) COMMENT 'Total engine/operating hours accumulated on this tyre across its entire service life (including prior fitments if retreaded or rotated). Sourced from Caterpillar MineStar or Infor EAM. Key metric for tyre life forecasting and TKPH compliance.',
    `accumulated_km` DECIMAL(18,2) COMMENT 'Total kilometres travelled by the tyre across its entire service life. Sourced from fleet management telematics. Used alongside accumulated_hours for tyre life benchmarking and rotation scheduling.',
    `application_code` STRING COMMENT 'TRA/ISO application category code indicating the equipment type the tyre is designed for: E=Earthmover/Off-the-Road, L=Loader, G=Grader, C=Compactor, IND=Industrial. Drives TKPH rating selection and procurement.. Valid values are `E|L|G|C|IND`',
    `axle_position` STRING COMMENT 'Axle group on which the tyre is mounted (front, rear, tag/pusher, or all for single-axle equipment). Complements position_code for load distribution and wear analysis.. Valid values are `front|rear|tag|all`',
    `compound_grade` STRING COMMENT 'OEM-designated rubber compound or product line grade (e.g., E4, L5, VSDP, XLDD2). Indicates the tyre construction and application suitability for specific haul road conditions.',
    `cost_per_hour` DECIMAL(18,2) COMMENT 'Calculated cost per operating hour in the operating currency, derived from purchase_cost divided by accumulated_hours at removal or current point in service. Key performance indicator for tyre vendor comparison and OPEX benchmarking.',
    `disposal_method` STRING COMMENT 'Method used for end-of-life tyre disposal. Null if tyre is still in service. Supports environmental compliance reporting under ISO 14001 and regulatory waste management obligations. Retreaded tyres re-enter service and generate a new tyre_record.. Valid values are `landfill|recycled|retreaded|crumbed_rubber|energy_recovery|returned_to_vendor`',
    `eam_asset_number` STRING COMMENT 'Infor EAM asset number assigned to this tyre as a tracked asset. Provides the cross-reference key between the tyre management system (Kal Tire TOMS / Klinge) and the Infor EAM asset register for maintenance cost allocation.',
    `haul_road_condition` STRING COMMENT 'Assessed condition rating of the primary haul road on which this tyre operated at time of removal. Contextualises tyre wear and damage patterns; poor haul road conditions are a leading cause of premature tyre failure in open-cut mining.. Valid values are `good|fair|poor|critical`',
    `inflation_pressure_kpa` DECIMAL(18,2) COMMENT 'Most recently recorded tyre inflation pressure in kilopascals (kPa) at the last inspection. Correct inflation is critical for tyre life, fuel efficiency, and safety. Compared against OEM-recommended cold inflation pressure.',
    `installation_date` DATE COMMENT 'Calendar date on which the tyre was fitted to the vehicle at the current position. Start of the active service period for accumulated hours and kilometres tracking.',
    `is_retreaded` BOOLEAN COMMENT 'Indicates whether the tyre currently in service is a retreaded carcass (True) or a new tyre (False). Retreaded tyres typically have different cost profiles and performance expectations.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent physical tyre inspection including tread depth measurement, visual damage check, and pressure verification. Drives inspection scheduling compliance.',
    `load_rating_kg` DECIMAL(18,2) COMMENT 'Maximum static load capacity in kilograms as specified by the OEM for this tyre at the recommended inflation pressure. Used to validate tyre fitment against vehicle gross vehicle mass (GVM) requirements.',
    `oem_brand` STRING COMMENT 'Tyre manufacturer brand name (e.g., Bridgestone, Michelin, Goodyear, Titan). Used for vendor performance comparison and procurement decisions.',
    `position_code` STRING COMMENT 'Standardised position code indicating where the tyre is mounted on the vehicle (e.g., LF=Left Front, RF=Right Front, LR=Left Rear, RR=Right Rear for rigid trucks; steer/drive/tag for articulated trucks). Used for rotation optimisation and wear pattern analysis. [ENUM-REF-CANDIDATE: LF|RF|LRI|LRO|RRI|RRO|steer|drive_left|drive_right|tag — promote to reference product]',
    `purchase_cost` DECIMAL(18,2) COMMENT 'Original purchase cost of the tyre in the operating currency. Used as the basis for cost per hour (CPH) and cost per kilometre calculations. Represents a significant component of mobile fleet Operating Expenditure (OPEX) at 10-15% of total.',
    `purchase_order_number` STRING COMMENT 'SAP or Pronto Xi purchase order number under which this tyre was procured. Enables traceability from tyre record back to procurement contract and vendor invoice for cost allocation and warranty claims.',
    `recommended_pressure_kpa` DECIMAL(18,2) COMMENT 'OEM-recommended cold inflation pressure in kilopascals (kPa) for this tyre size and load rating. Reference value for pressure compliance checks and deviation alerting.',
    `recorded_timestamp` TIMESTAMP COMMENT 'Timestamp when this tyre record was first created in the system, representing the record audit creation time. Supports data lineage, audit trail, and Silver layer ingestion tracking.',
    `removal_date` DATE COMMENT 'Calendar date on which the tyre was removed from the vehicle. Null if the tyre is currently in service. Combined with installation_date to calculate service duration.',
    `removal_reason` STRING COMMENT 'Reason code for tyre removal from service. Drives failure mode analysis, vendor performance benchmarking, and haul road condition assessment. [ENUM-REF-CANDIDATE: worn|damaged|rotated|scrapped|puncture|sidewall_failure|heat_separation|scheduled_change|bead_damage|cut — promote to reference product]',
    `retread_count` STRING COMMENT 'Number of times this tyre carcass has been retreaded. Tracks carcass reuse for cost optimisation and quality assurance. OEM carcass inspection standards typically limit retreads to 1-2 cycles for large OTR tyres.',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number stamped on the tyre sidewall. Used as the primary physical identifier for tyre tracking across its full lifecycle from receipt to disposal.',
    `size_specification` STRING COMMENT 'Standard tyre size designation in OEM format (e.g., 40.00R57, 27.00R49, 37.00R57). Encodes width, aspect ratio, and rim diameter per TRA/ETRTO standards. Critical for procurement and fitment compatibility.. Valid values are `^[0-9]{2,3}.[0-9]{2}R[0-9]{2,3}$`',
    `speed_rating_kmh` STRING COMMENT 'Maximum permissible operating speed in kilometres per hour as specified by the OEM. Relevant for haul road speed limit compliance and tyre selection for high-speed haulage applications.',
    `tkph_actual` DECIMAL(18,2) COMMENT 'Calculated actual TKPH value based on the haul truck payload, haul road distance, and cycle time recorded by Caterpillar MineStar. Compared against tkph_rating to assess thermal overload risk.',
    `tkph_rating` DECIMAL(18,2) COMMENT 'OEM-specified Tonne-Kilometres Per Hour (TKPH) rating for the tyre, representing the maximum thermal load the tyre can sustain. Compliance with TKPH rating is critical to prevent heat-related tyre failures in open-cut mining haul cycles.',
    `tread_depth_current_mm` DECIMAL(18,2) COMMENT 'Most recent tread depth measurement in millimetres recorded at the last inspection. Used to assess remaining tyre life and trigger rotation or replacement decisions.',
    `tread_depth_new_mm` DECIMAL(18,2) COMMENT 'Original tread depth in millimetres when the tyre was new, as specified by the OEM. Baseline reference for calculating tread wear percentage and remaining tread life.',
    `tread_depth_removal_mm` DECIMAL(18,2) COMMENT 'Tread depth in millimetres measured at the time of tyre removal. Null if tyre is still in service. Used to determine whether the tyre reached its designed wear limit or was removed prematurely.',
    `tyre_status` STRING COMMENT 'Current lifecycle state of the tyre. Tracks whether the tyre is actively mounted, held in the tyre bay, undergoing repair/retread, scrapped, or disposed. Supports inventory management and lifecycle cost analysis.. Valid values are `in_service|in_store|scrapped|repaired|retreaded|disposed`',
    `tyre_type` STRING COMMENT 'Tyre construction category indicating internal structure. Radial is standard for large haul trucks; bias ply used on some older or smaller equipment; solid and foam-filled used in specific underground or loader applications.. Valid values are `radial|bias|solid|foam_filled`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this tyre record, capturing inspection results, status changes, or measurement updates. Supports incremental data loading in the Databricks Silver layer.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the OEM or supplier warranty for this tyre expires. Enables timely warranty claims for premature failures and supports procurement negotiations with tyre vendors.',
    CONSTRAINT pk_tyre_record PRIMARY KEY(`tyre_record_id`)
) COMMENT 'Dedicated tyre management records for haul truck and mobile equipment tyres including tyre serial number, OEM brand and compound, size specification (e.g., 40.00R57), position on vehicle (LF, RF, LR, RR for rigid trucks; steer/drive for articulated), installation date, removal date, removal reason (worn, damaged, rotated, scrapped), accumulated hours and kilometres, tread depth measurements at each inspection, TKPH rating compliance, cost per hour, and disposal method. Tyre costs represent 10-15% of mobile fleet OPEX in open-cut mining. Supports tyre life forecasting, rotation optimisation, and vendor performance comparison. Sourced from tyre management systems (Klinge, Kal Tire TOMS) and Infor EAM.';

